INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (1, '紅蓮の剣士アレン', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/aren.png', '炎をまとう剣で戦う正統派の剣士。攻守のバランスに優れる。', 100, '2026-07-04 03:51:44', '2026-07-04 06:11:31');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (2, '氷結の魔女セレナ', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/serena.png', '氷の魔術を操る寡黙な魔女。広範囲の凍結攻撃を得意とする。', 100, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (3, '雷光の忍者リョウ', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/erika.png', '雷を纏い戦場を駆け抜ける忍者。素早さに特化した戦闘スタイル。', 95, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (4, '大地の巨人ドルグ', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/ignis.png', '岩の鎧を纏った巨人。圧倒的な防御力を誇る壁役。', 100, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (5, '疾風の弓使いエリカ', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/erika.png', '風を読む狩人。遠距離からの連続攻撃を得意とする。', 90, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (6, '闇夜の暗殺者クロウ', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/crow.png', '気配を消して敵の隙を突く暗殺者。奇襲を得意とする。', 95, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (7, '聖光の騎士アルフレッド', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/alfred.png', '聖なる光を纏う騎士。防御と回復に長けたバランス型。', 100, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (8, '毒霧の暗黒術士ヴェノム', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/venom.png', '毒と呪いを操る妖しい術士。継続ダメージで敵を蝕む。', 95, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (9, '鋼鉄の重戦車ゴライアス', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/crow.png', '全身を装甲で固めた人型兵器。圧倒的な防御力を持つ。', 100, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (10, '疾走する機械獣メカウルフ', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/kraken.png', '高速機動を得意とする機械の狼。奇襲と連撃が武器。', 95, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (11, '深海の魔物クラーケン', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/kraken.png', '深海に潜む巨大な触手の魔物。搦め捕るような戦法を得意とする。', 95, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (12, '砂漠の狂戦士ハディード', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/aren.png', '灼熱の砂漠を生き抜いた戦士。攻撃特化のリスキーな戦法を好む。', 95, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (13, '月光の巫女ルナ', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/luna.png', '月の力を借りる巫女。攻撃・回復どちらもこなす万能型。', 100, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (14, '業火の竜人イグニス', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/ignis.png', '竜の血を引く戦士。全身から炎を吹き上げて戦う。', 95, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (15, '氷雪の狼フェンリル', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/serena.png', '極寒の地に棲む伝説の狼。俊敏な動きで敵を翻弄する。', 98, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (16, '天空の剣聖ゼファー', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/zephyr.png', '空を舞う剣術の達人。攻守のバランスに優れた万能戦士。', 100, '2026-07-04 03:51:44', '2026-07-04 03:51:44');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (18, 'タミ', 'http://ss181301.stars.ne.jp/card_game/public/uploads/characters/080ca1d6-40d8-4a7e-a164-93cdd9ad5770.png', 'フットサルチームのマネージャー', 100, '2026-07-04 06:16:04', '2026-07-04 06:58:13');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (19, 'シライ', 'http://ss181301.stars.ne.jp/card_game/public/uploads/characters/fa3e19f1-0944-4b39-b242-93c3d755bf23.png', 'フットサルチームのリーダー', 100, '2026-07-04 06:30:04', '2026-07-04 06:58:27');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (20, 'イワルン', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/iwalun.png', 'つぶらな瞳を輝かせながら、いつも冷静に戦況を見つめるキツネ風のモンスター。小柄ながらも無駄のない洗練された動きを見せ、どんな局面にも対応できる天才肌。', 100, '2026-07-04 07:39:30', '2026-07-04 07:39:30');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (21, 'タシロップ', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/tasyrop.png', 'ひょろりと足が長い、ダチョウとカンガルーを合わせたようなモンスター。いつもご機嫌なリズムを刻むようにステップを踏みながら、驚異的なキープ力で敵を翻弄する。', 100, '2026-07-04 07:39:30', '2026-07-04 07:39:30');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (22, 'タカハピ', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/takahapi.png', 'まんまるでお餅のような、見るからに優しそうな癒やし系モンスター。いつもニコニコしているが、頭の中は超高速で計算が回っており、的確な指示で仲間を導く。', 100, '2026-07-04 07:39:30', '2026-07-04 07:39:30');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (23, 'ネギルじい', 'http://ss181301.stars.ne.jp/card_game/public/uploads/characters/a128a593-5cc8-4d37-a243-ea7a125cc2ea.png', '小さな杖を突いた、白いおひげがチャームポイントの古老モンスター。普段はのんびりしているが、いざ戦い(交渉)が始まると、現役時代を彷彿とさせる凄まじい眼光とトーク術を見せる。', 100, '2026-07-04 07:39:30', '2026-07-04 07:41:50');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (24, 'タニョン', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/tanyon.png', '最近、幸せオーラで身体が少しピンクがかった、カワウソ風のモンスター。常に落ち着いていて滅多に慌てず、ピッチに立てば一転して流れるような美しいボール捌きを見せる。', 100, '2026-07-04 07:39:30', '2026-07-04 07:39:30');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (25, 'カネマール', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/kanemar.png', '大きな耳が特徴的な、ウサギ風のモンスター。視野が非常に広く、地面の小さなハーブから空の雲の動きまで気が付く。仲間とのコンビネーションで真価を発揮する。', 100, '2026-07-04 07:39:30', '2026-07-04 07:39:30');
INSERT INTO characters (id, name, image_url, description, total_points, created_at, updated_at) VALUES (26, 'センゴクン', 'http://ss181301.stars.ne.jp/card_game/public/characters/sample/sengokun.png', '普段は巣穴でコツコツと自分の仕事(タスク)をこなしている真面目なクマ風モンスター。時々ひょっこり現れては、誰も真似できない規格外の大砲シュートをぶっ放していく。', 100, '2026-07-04 07:39:30', '2026-07-04 07:39:30');
