INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (3, 2, '絶対零度', '敵全体を凍りつかせ、行動不能に近い状態に陥れる。', '世界が凍りつき、時が止まる。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (4, 3, '雷閃刃', '雷速の斬撃を敵に叩き込む。', '雷光一閃、敵が反応する間もない。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (5, 3, '分身の術', '残像を作り出し、次の攻撃の回避率を高める。', '幾重にも重なる影が敵を惑わす。', 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (6, 4, '大地割断', '拳を地面に叩きつけ、衝撃波で敵陣を揺るがす。', '大地が唸り、敵の足元が崩れ落ちる。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (7, 5, '疾風連射', '矢を立て続けに放ち、敵単体に連続ダメージを与える。', '風のように放たれる矢の雨。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (8, 5, '風纏いの矢', '風の力を纏わせた一撃必殺の矢を放つ。', '風を切り裂く一矢が命中する。', 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (9, 6, '闇討ちの一閃', '死角から急所を狙う一撃で大ダメージを与える。', '闇に紛れた刃が敵を貫く。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (10, 7, '聖光の裁き', '聖なる光の柱を敵に落とし、大ダメージを与える。', '天より降り注ぐ光が悪を裁く。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (11, 7, '守護の誓い', '味方をかばい、自身の防御力を一時的に高める。', '盾となりし誓いは決して揺るがない。', 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (12, 8, '猛毒の霧', '紫の霧を発生させ、敵全体に継続ダメージを与える。', '紫煙が広がり、敵の生命力を静かに蝕む。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (13, 9, '主砲斉射', '両肩の主砲から敵全体へ砲撃を放つ。', '轟音とともに鋼鉄の雷が降り注ぐ。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (14, 9, '装甲展開', '追加装甲を展開し、一時的に防御力を大幅に高める。', '鋼の装甲が唸りを上げて展開される。', 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (15, 10, '超音速タックル', '音速を超える突進で敵を吹き飛ばす。', '轟音を置き去りにする一撃が炸裂する。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (16, 11, '触手絡め', '無数の触手で敵を締め上げ、行動を封じる。', '闇の底から伸びる触手が敵を捕らえる。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (17, 11, '深海の咆哮', '咆哮で敵全体を怯ませ、命中率を下げる。', '海底を震わせる咆哮が響き渡る。', 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (18, 12, '砂塵の乱舞', '砂塵を巻き上げながら乱れ打つ連続攻撃。', '砂嵐と共に刃が乱舞する。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (19, 13, '月光浄化', '月光を集め、敵単体に浄化の光を浴びせる。', '静謐な月光が全てを照らし出す。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (20, 13, '癒しの祈り', '味方の傷を癒し、体力を回復させる。', '祈りの声とともに温かな光が包み込む。', 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (21, 14, '滅焦竜炎', '口から吐き出す業火の息で敵を焼き尽くす。', '竜の咆哮と共に大地が焦土と化す。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (22, 15, '氷牙の一撃', '凍える牙で敵に噛みつき、大ダメージを与える。', '氷の牙が敵の体温を奪い去る。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (23, 15, '白銀の咆哮', '咆哮で吹雪を呼び、敵全体の素早さを下げる。', '白銀の吹雪が戦場を包み込む。', 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (24, 16, '天翔閃光斬', '空高く舞い上がり、光速の斬撃で敵を貫く。', '天を翔ける閃光が敵を切り裂く。', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (29, 1, '紅蓮斬', '刀身を炎で覆い、前方の敵を薙ぎ払う。', '紅蓮の斬撃が闇を切り裂く!', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (30, 1, '不死鳥の舞', '自らを炎で包み、体力の一部を回復しながら反撃態勢に入る。', '灰の中から不死鳥の如く蘇る。', 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (45, 18, '原因切り分け', 'エラーの原因を特定して、問題の核心を突く', 'エラーの原因を特定して、問題の核心を突く', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (46, 18, '解決サポート連携', '関連サービスを確認し、最適な解決策を実行する', '関連サービスを確認し、最適な解決策を実行する', 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (47, 19, 'ストロングウォーク', '前へ力強く進み、仲間の体力を回復しながら味方全体の防御力を2段階上げる', '前へ力強く進み、仲間の体力を回復しながら味方全体の防御力を2段階上げる', 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (48, 19, 'アースブレイクシュート', '大地を踏みしめ、強烈なシュートを放つ。\n相手に大ダメージを与えて、守備力を1段階下げる', '大地を踏みしめ、強烈なシュートを放つ。\n相手に大ダメージを与えて、守備力を1段階下げる', 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (49, 20, 'クレバー・スピード', '相手の動きを完璧に予測し、一瞬の隙を突いて華麗に回り込む体当たり。', NULL, 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (50, 20, '万能スターダスト', '星のエネルギーを全身に纏い、攻撃・防御のどちらにも転化できる万能の光を放つ。', NULL, 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (51, 21, 'イノセント・ドリブル', '高い打点から繰り出される予測不能なステップで、相手の間をスイスイとすり抜ける。', NULL, 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (52, 21, '終わりなき美メロ', '大好きなメロディを口ずさみ、聴いた相手をうっとりさせて動きを鈍らせる。', NULL, 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (53, 22, 'おおらかな盾', '敵の攻撃すら包み込むようなオーラを放ち、味方へのダメージを完全に肩代わりする。', NULL, 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (54, 22, '必勝の数式(ロジック)', '瞬時に相手の弱点確率を計算し、味方の攻撃が必ず急所に当たるようにナビゲートする。', NULL, 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (57, 24, 'マリッジ・ステップ', '幸せいっぱいの軽快な身のこなしで、敵の激しい突進をひらりとかわす。', NULL, 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (58, 24, 'セレニティ・キック', '完全にリラックスした状態から、針の穴を通すような正確無比なシュートを放つ。', NULL, 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (59, 25, 'パス・リンク', '味方の位置を完璧に把握し、目にも留まらぬスピードで最適な位置へパス(魔力)を繋ぐ。', NULL, 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (60, 25, 'スポット・ディテクト', '相手の装備や構えの「ほんのわずかな綻び」を見つけ出し、味方にそこを突かせる。', NULL, 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (61, 26, 'ルーティン・バースト', '日頃の規則正しい生活で蓄積されたエネルギーを一気に解放する、超重量級の体当たり。', NULL, 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (62, 26, 'レア・エンカウント・キャノン', 'めったに見られない本気の構えから、重力をねじ曲げるほどの超強力なエネルギー弾を放つ。', NULL, 1);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (63, 23, '伝説のクロージング', '圧倒的な熱量とマシンガントーク(鳴き声)で、相手をいつの間にか自分のペースに巻き込む。', NULL, 0);
INSERT INTO special_moves (id, character_id, name, description, flavor_text, sort_order) VALUES (64, 23, 'ベテランズ・ホイッスル', '鋭い笛の音で味方の闘志に火をつけ、秘められた能力を一時的に限界突破させる。', NULL, 1);
