INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (1, 1, 2, 'completed', 'teamB', 9, '鋼鉄の重戦車ゴライアス', 'サンプルデッキAは前衛4体全員が攻守バランスに優れるが、素早さや特殊耐性にやや劣る', 'サンプルデッキBは防御力が極めて高く、硬質な重戦車や高火力の砂漠の狂戦士が戦闘を有利に進めやすい', 'teamB', '{\n  "analysis": {\n    "teamA": "サンプルデッキAは前衛4体全員が攻守バランスに優れるが、素早さや特殊耐性にやや劣る",\n    "teamB": "サンプルデッキBは防御力が極めて高く、硬質な重戦車や高火力の砂漠の狂戦士が戦闘を有利に進めやすい",\n    "predictedWinner": "teamB"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "チームBの砂漠の狂戦士ハディードが砂塵の乱舞を放ち、チームAの紅蓮の剣士アレンに炎の砂嵐を食らわせ、18ポイントのダメージ！体力が2へと激減！"\n    },\n    {\n      "turn": 2,\n      "message": "チームBの深海の魔物クラーケンが触手絡めで氷結の魔女セレナの足元を締め付け、5ポイントのダメージと凍結の恐怖を与える！"\n    },\n    {\n      "turn": 3,\n      "message": "チームBの鋼鉄の重戦車ゴライアスが主砲斉射で雷光の忍者リョウに直撃、12ポイントの爆撃！体力が3に激減！"\n    },\n    {\n      "turn": 4,\n      "message": "チームBの闇夜の暗殺者クロウが闇討ちの一閃で大地の巨人ドルグの弱点を突き、20ポイントの致命的ダメージ！体力が5に激減！"\n    },\n    {\n      "turn": 5,\n      "message": "チームBの深海の魔物クラーケンが再び触手絡めで倒れた紅蓮の剣士アレンに決定的一撃、残体力0となり戦闘不能に！"\n    },\n    {\n      "turn": 6,\n      "message": "チームBの鋼鉄の重戦車ゴライアスが残された氷結の魔女セレナに主砲斉射を浴みせ、8ポイントのダメージで体力を7に削る！"\n    },\n    {\n      "turn": 7,\n      "message": "チームBの砂漠の狂戦士ハディードが再び砂塵の乱舞を放ち、氷結の魔女セレナに10ポイントの連続ダメージ！体力が0に倒れ、チームA全体が戦闘不能となり試合終了！"\n    },\n    {\n      "turn": 8,\n      "message": "最終的にチームBが勝利！最前線で貢献した『鋼鉄の重戦車ゴライアス』がMVPに輝く！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sandstorm"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "bind"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "cannon"\n    },\n    {\n      "type": "special_move",\n      "character": "闇夜の暗殺者クロウ",\n      "effect": "critical"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "bind"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "cannon"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sandstorm"\n    }\n  ],\n  "result": {\n    "winner": "teamB",\n    "mvp": "鋼鉄の重戦車ゴライアス"\n  }\n}', NULL, '2026-07-04 03:53:21', '2026-07-04 03:54:12');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (2, 1, 2, 'completed', 'teamA', 2, '氷結の魔女セレナ', 'Team A combines flame, ice, speed, and earth with defensive strength and versatile support, while Team B relies on heavy armor, raw damage, and crowd control; the ice freeze and revival options give Team A a strategic edge, leading to a predicted advantage.', 'Team B fields a heavily armored tank, a fast mech, a high‑HP deep‑sea monster and an aggressive desert warrior, offering strong offense and durability but limited mobility and no healing, making them vulnerable to freeze and focused attacks.', 'teamA', '{\n  "analysis": {\n    "teamA": "Team A combines flame, ice, speed, and earth with defensive strength and versatile support, while Team B relies on heavy armor, raw damage, and crowd control; the ice freeze and revival options give Team A a strategic edge, leading to a predicted advantage.",\n    "teamB": "Team B fields a heavily armored tank, a fast mech, a high‑HP deep‑sea monster and an aggressive desert warrior, offering strong offense and durability but limited mobility and no healing, making them vulnerable to freeze and focused attacks.",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "鋼鉄の重戦車ゴライアス (Team B) fires 主砲斉射, blasting all front enemies of Team A with steel thunder."\n    },\n    {\n      "turn": 2,\n      "message": "紅蓮の剣士アレン (Team A) counters with 紅蓮斬 on ゴライアス, igniting the armor and reducing its defense."\n    },\n    {\n      "turn": 3,\n      "message": "疾走する機械獣メカウルフ (Team B) attempts 超音速タックル on 紅光の忍者リョウ, but the swift strike is dodged."\n    },\n    {\n      "turn": 4,\n      "message": "紅光の忍者リョウ (Team A) executes 雷閃刃 on 疾走する機械獣メカウルフ, slicing through its chassis and knocking it out."\n    },\n    {\n      "turn": 5,\n      "message": "氷結の魔女セレナ (Team A) chants 絶対零度, freezing all remaining Team B front units in place."\n    },\n    {\n      "turn": 6,\n      "message": "大地の巨人ドルグ (Team A) slams the ground with 大地割断, shaking the frozen クラーケン and cracking its icy hide."\n    },\n    {\n      "turn": 7,\n      "message": "砂漠の狂戦士ハディード (Team B) is immobilized by the ice and cannot act this turn."\n    },\n    {\n      "turn": 8,\n      "message": "闇夜の暗殺者クロウ (Team A) slips into the shadows and strikes with 闇討ちの一閃, eliminating ハディード."\n    },\n    {\n      "turn": 9,\n      "message": "業火の竜人イグニス (Team B) tries to unleash 滅焦竜炎 on セレナ, but the frozen state prevents him from channeling fire."\n    },\n    {\n      "turn": 10,\n      "message": "聖光の騎士アルフレッド (Team A) raises his shield with 守護の誓い, bolstering defense of his allies."\n    },\n    {\n      "turn": 11,\n      "message": "全敵が戦闘不能に追い込まれたため、Team B withdraws; Team A emerges victorious!"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "steel_thunder"\n    },\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "紅光の忍者リョウ",\n      "effect": "lightning"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "freeze"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "earthquake"\n    },\n    {\n      "type": "special_move",\n      "character": "闇夜の暗殺者クロウ",\n      "effect": "assassin_strike"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "氷結の魔女セレナ"\n  }\n}', NULL, '2026-07-04 04:03:35', '2026-07-04 04:04:45');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (3, 1, 2, 'completed', 'teamA', 1, '紅蓮の剣士アレン', 'サンプルデッキA：前衛4体（紅蓮の剣士アレン、氷結の魔女セレナ、雷光の忍者リョウ、大地の巨人ドルグ）と控え4体（疾風の弓使いエリカ、闇夜の暗殺者クロウ、聖光の騎士アルフレッド、毒霧の暗黒術士ヴェノム）からなる', 'サンプルデッキB：前衛4体（鋼鉄の重戦車ゴライアス、疾走する機械獣メカウルフ、深海の魔物クラーケン、砂漠の狂戦士ハディード）と控え4体（月光の巫女ルナ、業火の竜人イグニス、氷雪の狼フェンリル、天空の剣聖ゼファー）からなる', 'teamA', '{\n  "analysis": {\n    "teamA": "サンプルデッキA：前衛4体（紅蓮の剣士アレン、氷結の魔女セレナ、雷光の忍者リョウ、大地の巨人ドルグ）と控え4体（疾風の弓使いエリカ、闇夜の暗殺者クロウ、聖光の騎士アルフレッド、毒霧の暗黒術士ヴェノム）からなる",\n    "teamB": "サンプルデッキB：前衛4体（鋼鉄の重戦車ゴライアス、疾走する機械獣メカウルフ、深海の魔物クラーケン、砂漠の狂戦士ハディード）と控え4体（月光の巫女ルナ、業火の竜人イグニス、氷雪の狼フェンリル、天空の剣聖ゼファー）からなる",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "戦闘開始！ 前衛の紅蓮の剣士アレンが先手を取り、紅蓮斬で深海の魔物クラーケンへ炎の斬撃を放つ。"\n    },\n    {\n      "turn": 2,\n      "message": "続く疾走する機械獣メカウルフが超音速タックルで大地の巨人ドルグに直撃、しかしドルグの装甲が光り防御力が上がる。"\n    },\n    {\n      "turn": 3,\n      "message": "氷結の魔女セレナが絶対零度を発動し、クラーケンを凍結させて行動不能に近い状態にする。"\n    },\n    {\n      "turn": 4,\n      "message": "砂漠の狂戦士ハディードが砂塵の乱舞で雷光の忍者リョウに連続攻撃、リョウは分身の術で回避率を上げる。"\n    },\n    {\n      "turn": 5,\n      "message": "鋼鉄の重戦車ゴライアスが主砲斉射で前衛全員に大ダメージ、だがドルグが大地割断でゴライアスの足元を崩し、転倒させる。"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "freeze"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', NULL, '2026-07-04 04:08:29', '2026-07-04 04:08:42');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (4, 1, 2, 'completed', 'teamA', 1, '紅蓮の剣士アレン', 'Team A balances offense and recovery, with strong frontline attackers and versatile support, giving them adaptability.', 'Team B relies on heavy defense and high attack but lacks agility and sustain, making them vulnerable to coordinated strikes.', 'teamA', '{\n  "analysis": {\n    "teamA": "Team A balances offense and recovery, with strong frontline attackers and versatile support, giving them adaptability.",\n    "teamB": "Team B relies on heavy defense and high attack but lacks agility and sustain, making them vulnerable to coordinated strikes.",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "第1ターン！雷光の忍者リョウが「雷閃刃」で疾走する機械獣メカウルフへ直撃！反撃の「超音速タックル」で紅蓮の剣士アレンに衝撃！続いて砂漠の狂戦士ハディードが「砂塵の乱舞」で大地の巨人ドルグを圧迫！ 紅蓮の剣士アレンは「紅蓮斬」で深海の魔物クラーケンの触手を切り裂き、最後に鋼鉄の重戦車ゴライアスが「主砲斉射」で全体に砲撃！"\n    },\n    {\n      "turn": 2,\n      "message": "第2ターン！氷結の魔女セレナが「絶対零度」で深海の魔物クラーケンを凍結させ、行動不能に！疾風の弓使いエリカが「疾風連射」で砂漠の狂戦士ハディードに連続ダメージ！クラーケンは「触手絡め」でさらなる行動不能！"\n    },\n    {\n      "turn": 3,\n      "message": "第3ターン！大地の巨人ドルグが「大地割断」でクラーケンの足元を崩し、倒壊させる！ 鋼鉄の重戦車ゴライアスは「装甲展開」で防御を強化するが、すでに致命的なダメージを受けている！"\n    },\n    {\n      "turn": 4,\n      "message": "第4ターン！紅蓮の剣士アレンが「不死鳥の舞」で自己回復し、疾風の弓使いエリカが「風纏いの矢」で鋼鉄の重戦車ゴライアスに決定的一撃！チームB全勢が戦闘不能となり、チームAの勝利！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "雷光の忍者リョウ",\n      "effect": "lightning"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "impact"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sand"\n    },\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "bullet"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "freeze"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "bind"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "earth"\n    },\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "heal"\n    },\n    {\n      "type": "special_move",\n      "character": "疾風の弓使いエリカ",\n      "effect": "wind"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', NULL, '2026-07-04 04:13:10', '2026-07-04 04:13:41');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (5, 1, 2, 'completed', 'teamA', 6, '闇夜の暗殺者クロウ', 'サンプルデッキA', 'サンプルデッキB', 'teamA', '{\n  "analysis": {\n    "teamA": "サンプルデッキA",\n    "teamB": "サンプルデッキB",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "team Bの砂漠の狂戦士ハディードが砂塵の乱舞を放ち、紅蓮の剣士アレンに45の連続ダメージ！"\n    },\n    {\n      "turn": 2,\n      "message": "team Aの雷光の忍者リョウが雷閃刃で鋼鉄の重戦車ゴライアスに30の直接ダメージ！"\n    },\n    {\n      "turn": 3,\n      "message": "team Bの疾走する機械獣メカウルフが超音速タックルで雷光の忍者リョウに32の致命的打撃！"\n    },\n    {\n      "turn": 4,\n      "message": "team Aの氷結の魔女セレナが絶対零度で全敵を凍結させ、行動を封じる！"\n    },\n    {\n      "turn": 5,\n      "message": "team Bの深海の魔物クラーケンが触手絡めで氷結の魔女セレナを拘束！"\n    },\n    {\n      "turn": 6,\n      "message": "team Aの大地の巨人ドルグが大地割断で深海の魔物クラーケンに25のダメージ！"\n    },\n    {\n      "turn": 7,\n      "message": "team Bの砂漠の狂戦士ハディードが再び砂塵の乱舞を使用し、大地の巨人ドルグに45のダメージ！"\n    },\n    {\n      "turn": 8,\n      "message": "team Bの深海の魔物クラーケンが深海の咆哮で場を揺らすが、ダメージはなし！"\n    },\n    {\n      "turn": 9,\n      "message": "team Aの大地の巨人ドルグが大地割断で深海の魔物クラーケンを撃破！"\n    },\n    {\n      "turn": 10,\n      "message": "team Bの砂漠の狂戦士ハディードが砂塵の乱舞で大地の巨人ドルグを倒す！"\n    },\n    {\n      "turn": 11,\n      "message": "team Aの闇夜の暗殺者クロウが闇討ちの一閃で砂漠の狂戦士ハディードを倒し、勝利！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "雷光の忍者リョウ",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "freeze"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "闇夜の暗殺者クロウ",\n      "effect": "damage"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "闇夜の暗殺者クロウ"\n  }\n}', NULL, '2026-07-04 04:15:31', '2026-07-04 04:16:26');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (6, 1, 2, 'completed', 'teamA', 1, '紅蓮の剣士アレン', 'Team A possesses a balanced mix of fire, ice, lightning, earth, and support roles, with strong defensive giant and versatile reserve options.', 'Team B relies on heavy armor, high‑speed mechanized units, and elemental beasts, offering high offense but lower overall durability.', 'teamA', '{\n  "analysis": {\n    "teamA": "Team A possesses a balanced mix of fire, ice, lightning, earth, and support roles, with strong defensive giant and versatile reserve options.",\n    "teamB": "Team B relies on heavy armor, high‑speed mechanized units, and elemental beasts, offering high offense but lower overall durability.",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "紅蓮の剣士アレンが『紅蓮斬』を使用し、鋼鉄の重戦車ゴライアスを倒した。"\n    },\n    {\n      "turn": 2,\n      "message": "疾走する機械獣メカウルフが『超音速タックル』で雷光の忍者リョウを倒した。"\n    },\n    {\n      "turn": 3,\n      "message": "深海の魔物クラーケンが『触手絡め』で大地の巨人ドルグを倒した。"\n    },\n    {\n      "turn": 4,\n      "message": "砂漠の狂戦士ハディードが『砂塵の乱舞』で疾風の弓使いエリカを倒した。"\n    },\n    {\n      "turn": 5,\n      "message": "紅蓮の剣士アレンが『不死鳥の舞』で自身を回復した。"\n    },\n    {\n      "turn": 6,\n      "message": "月光の巫女ルナが『癒しの祈り』で自身を回復した。"\n    },\n    {\n      "turn": 7,\n      "message": "闇夜の暗殺者クロウが『闇討ちの一閃』で業火の竜人イグニスを倒した。"\n    },\n    {\n      "turn": 8,\n      "message": "氷雪の狼フェンリルが『氷牙の一撃』で紅蓮の剣士アレンを倒した。"\n    },\n    {\n      "turn": 9,\n      "message": "氷結の魔女セレナが『絶対零度』で氷雪の狼フェンリルを倒した。"\n    },\n    {\n      "turn": 10,\n      "message": "聖光の騎士アルフレッドが『聖光の裁き』で月光の巫女ルナを倒した。"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "steel"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "bind"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sand"\n    },\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "recovery"\n    },\n    {\n      "type": "special_move",\n      "character": "月光の巫女ルナ",\n      "effect": "heal"\n    },\n    {\n      "type": "special_move",\n      "character": "闇夜の暗殺者クロウ",\n      "effect": "dark"\n    },\n    {\n      "type": "special_move",\n      "character": "氷雪の狼フェンリル",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "freeze"\n    },\n    {\n      "type": "special_move",\n      "character": "聖光の騎士アルフレッド",\n      "effect": "light"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', NULL, '2026-07-04 04:26:22', '2026-07-04 04:26:46');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (7, 1, 2, 'completed', 'teamA', 1, '紅蓮の剣士アレン', 'サンプルデッキAは、炎・氷・雷・大地と四属性のバランスが取れた前衛構成。攻撃力・防御力・素早さのバランスが良く、必殺技で相手の行動を封じたり持続ダメージを与える能力が豊富。一方、相手チームBは防御力が極めて高い装甲兵器や高HPの触手生物を擁するが、素早さや回復手段が乏しく、属性弱化や解除が難しい。 thus teamA holds a strategic advantage in attrition and elemental coverage.', 'サンプルデッキBは、装甲重戦車・高速機械獣・深海触手・砂漠の狂戦士という四体の前衛が揃える。防御力・体力・攻撃特化が極端で、特に装甲展開や主砲斉射で大量の即時ダメージを与えるが、回復や状態異常回避手段が限定的。属性的に炎・氷・雷・土と対抗できるが、全体的に素早さが低く、連続攻撃に弱い構造。', 'teamA', '{\n  "analysis": {\n    "teamA": "サンプルデッキAは、炎・氷・雷・大地と四属性のバランスが取れた前衛構成。攻撃力・防御力・素早さのバランスが良く、必殺技で相手の行動を封じたり持続ダメージを与える能力が豊富。一方、相手チームBは防御力が極めて高い装甲兵器や高HPの触手生物を擁するが、素早さや回復手段が乏しく、属性弱化や解除が難しい。 thus teamA holds a strategic advantage in attrition and elemental coverage.",\n    "teamB": "サンプルデッキBは、装甲重戦車・高速機械獣・深海触手・砂漠の狂戦士という四体の前衛が揃える。防御力・体力・攻撃特化が極端で、特に装甲展開や主砲斉射で大量の即時ダメージを与えるが、回復や状態異常回避手段が限定的。属性的に炎・氷・雷・土と対抗できるが、全体的に素早さが低く、連続攻撃に弱い構造。",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "▶️ 第1ターン！　紅蓮の剣士アレンが炎の刃『紅蓮斬』で鋼鉄の重戦車ゴライアスに10点の炎ダメージ！　続くゴライアスが主砲斉射で炎の剣士に12点の衝撃を返す！"\n    },\n    {\n      "turn": 2,\n      "message": "▶️ 第2ターン！　氷結の魔女セレナが『絶対零度』で機械獣メカウルフを凍結させ、行動を封じる！　メカウルフは『超音速タックル』で氷結の魔女に17点の打撃を与え、体力を激減させた！"\n    },\n    {\n      "turn": 3,\n      "message": "▶️ 第3ターン！　雷光の忍者リョウが『雷閃刃』で深海の魔物クラーケンに5点の雷撃！　クラーケンは『触手絡め』でリョウを締め付け、回避率を低下させる！"\n    },\n    {\n      "turn": 4,\n      "message": "▶️ 第4ターン！　大地の巨人ドルグが『大地割断』で砂漠の狂戦士ハディードを0点に粉砕！　クラーケンが『深海の咆哮』で全体の行動速度を一瞬だけ低下させた！"\n    },\n    {\n      "turn": 5,\n      "message": "▶️ 第5ターン！　残っていた重戦車ゴライアスが7点の体力で倒れ、前衛全滅！　最後に紅蓮の剣士アレンが残りの敵を炎の刃で粉砕し、チームAの勝利が確定した！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "kinetic"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "freeze"\n    },\n    {\n      "type": "special_move",\n      "character": "雷光の忍者リョウ",\n      "effect": "lightning"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "earthquake"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', NULL, '2026-07-04 04:28:26', '2026-07-04 04:28:53');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (8, 1, 2, 'completed', 'teamA', 1, '紅蓮の剣士アレン', 'サンプルデッキAは、炎の剣士、氷魔術、雷忍者、岩巨人の4体からなる多彩な前衛を持ち、防御力が高く広範囲の凍結や炎の回復といった多様な必殺技を保有する。', 'サンプルデッキBは、装甲重戦車、高速機械狼、深海触手、砂漠の狂戦士という4体の前衛を持ち、極端な攻撃力と防御力のバランスが取れたチームだが、支援能力は限定的である。', 'teamA', '{\n  "analysis": {\n    "teamA": "サンプルデッキAは、炎の剣士、氷魔術、雷忍者、岩巨人の4体からなる多彩な前衛を持ち、防御力が高く広範囲の凍結や炎の回復といった多様な必殺技を保有する。",\n    "teamB": "サンプルデッキBは、装甲重戦車、高速機械狼、深海触手、砂漠の狂戦士という4体の前衛を持ち、極端な攻撃力と防御力のバランスが取れたチームだが、支援能力は限定的である。",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "ターン1：チームAの紅蓮の剣士アレンが必殺技『紅蓮斬』を使用しチームBの鋼鉄の重戦車ゴライアスへ炎の斬撃を叩き込む演出：紅蓮の斬撃が闇を切り裂く！"\n    },\n    {\n      "turn": 2,\n      "message": "ターン2：チームBの疾走する機械獣メカウルフが必殺技『超音速タックル』でチームAの大地の巨人ドルグへ高速突進し衝撃波で防御を低下させる演出：轟音を置き去りにする一撃が炸裂する！"\n    },\n    {\n      "turn": 3,\n      "message": "ターン3：チームAの氷結の魔女セレナが必殺技『絶対零度』でチームBの深海の魔物クラーケン全体を凍りつかせる演出：世界が凍りつき、時が止まる！"\n    },\n    {\n      "turn": 4,\n      "message": "ターン4：チームBの砂漠の狂戦士ハディードが必殺技『砂塵の乱舞』でチームAの雷光の忍者リョウに砂の連射を浴びせる演出：砂嵐と共に刃が乱舞する！"\n    },\n    {\n      "turn": 5,\n      "message": "ターン5：チームAの大地の巨人ドルグが必殺技『大地割断』でチームBの砂漠の狂戦士ハディードへ地震波を叩き込み撃破演出：大地が唸り、敵の足元が崩れ落ちる！"\n    },\n    {\n      "turn": 6,\n      "message": "ターン6：チームBの残り前衛が全滅しチームAが勝利！チームAの紅蓮の剣士アレンが最も活躍しMVPに選出される！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "speed"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sand"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "earth"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', NULL, '2026-07-04 04:35:48', '2026-07-04 04:36:06');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (9, 1, 2, 'completed', 'teamA', 1, '紅蓮の剣士アレン', 'サンプルデッキAは、炎の剣士、氷の魔術、雷速の忍者、岩の巨人の四体で構成し、バランスの取れた攻撃力、防御力、回復力、広域凍結能力を備えている。', 'サンプルデッキBは、装甲重戦車、高速機械狼、深海の触手魔物、砂漠の狂戦士の四体で構成し、高攻撃力と特殊な広域攻撃を持つが防御力が低く脆い。', 'teamA', '{\n  "analysis": {\n    "teamA": "サンプルデッキAは、炎の剣士、氷の魔術、雷速の忍者、岩の巨人の四体で構成し、バランスの取れた攻撃力、防御力、回復力、広域凍結能力を備えている。",\n    "teamB": "サンプルデッキBは、装甲重戦車、高速機械狼、深海の触手魔物、砂漠の狂戦士の四体で構成し、高攻撃力と特殊な広域攻撃を持つが防御力が低く脆い。",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "紅蓮の剣士アレンは『不死鳥の舞』を使用し、炎で自分を包んで体力を回復し、反撃態勢に入る。"\n    },\n    {\n      "turn": 2,\n      "message": "鋼鉄の重戦車ゴライアスは『主砲斉射』を発射し、全敵に砲撃を命中させる。"\n    },\n    {\n      "turn": 3,\n      "message": "氷結の魔女セレナは『絶対零度』を放ち、敵全体を凍りつかせて行動不能に近い状態にする。"\n    },\n    {\n      "turn": 4,\n      "message": "雷光の忍者リョウは『雷閃刃』を使用し、前方の敵に雷速の斬撃を叩き込む。"\n    },\n    {\n      "turn": 5,\n      "message": "深海の魔物クラーケンは『触手絡め』で触手で敵を締め上げ、行動を封じる。"\n    },\n    {\n      "turn": 6,\n      "message": "大地の巨人ドルグは『大地割断』で拳を地面に叩きつけ、衝撃波で敵陣を揺るがす。"\n    },\n    {\n      "turn": 7,\n      "message": "砂漠の狂戦士ハディードは『砂塵の乱舞』で砂塵を巻き上げ、連続攻撃を繰り広げる。"\n    },\n    {\n      "turn": 8,\n      "message": "紅蓮の剣士アレンは『紅蓮斬』で炎の刀撃を放ち、敵を薙ぎ払う。"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "heal"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "freeze"\n    },\n    {\n      "type": "special_move",\n      "character": "雷光の忍者リョウ",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "bind"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "damage"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', NULL, '2026-07-04 04:36:13', '2026-07-04 04:36:42');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (10, 1, 2, 'completed', 'teamA', 6, '闇夜の暗殺者クロウ', 'サンプルデッキAは、攻守のバランスが取れた前衛4体と多彩な支援キャラを持ち、回復・防御・特殊攻撃に強みを持つ。', 'サンプルデッキBは、高攻撃・高防御の前衛ユニットと多彩な特技を持つが、素早さと回復力にやや劣る。', 'teamA', '{\n  "analysis": {\n    "teamA": "サンプルデッキAは、攻守のバランスが取れた前衛4体と多彩な支援キャラを持ち、回復・防御・特殊攻撃に強みを持つ。",\n    "teamB": "サンプルデッキBは、高攻撃・高防御の前衛ユニットと多彩な特技を持つが、素早さと回復力にやや劣る。",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "鋼鉄の重戦車ゴライアス が 紅蓮の剣士アレン に 主砲斉射 を放ち、炎の砲撃で倒れた！"\n    },\n    {\n      "turn": 2,\n      "message": "闇夜の暗殺者クロウ が 鋼鉄の重戦車ゴライアス に 闇討ちの一閃 を敢然と使用し、瞬時に倒れた！"\n    },\n    {\n      "turn": 3,\n      "message": "氷結の魔女セレナ が 絶対零度 を唱え、全敵を凍りつかせる！"\n    },\n    {\n      "turn": 4,\n      "message": "疾走する機械獣メカウルフ が 雷光の忍者リョウ に 超音速タックル を命中させ、倒れた！"\n    },\n    {\n      "turn": 5,\n      "message": "砂漠の狂戦士ハディード が 砂塵の乱舞 を繰り出し、大地の巨人ドルグ を砂嵐に飲み込んで倒れた！"\n    },\n    {\n      "turn": 6,\n      "message": "疾風の弓使いエリカ が 疾風連射 で 疾走する機械獣メカウルフ を貫き、倒れた！"\n    },\n    {\n      "turn": 7,\n      "message": "聖光の騎士アルフレッド が 聖光の裁き を放ち、深海の魔物クラーケン を光の刃で切り裂いた！"\n    },\n    {\n      "turn": 8,\n      "message": "毒霧の暗黒術士ヴェノム が 猛毒の霧 を発動し、砂漠の狂戦士ハディード を毒で蝕んで倒れた！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "闇夜の暗殺者クロウ",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "freeze"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "impact"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sandstorm"\n    },\n    {\n      "type": "special_move",\n      "character": "疾風の弓使いエリカ",\n      "effect": "arrow"\n    },\n    {\n      "type": "special_move",\n      "character": "聖光の騎士アルフレッド",\n      "effect": "light"\n    },\n    {\n      "type": "special_move",\n      "character": "毒霧の暗黒術士ヴェノム",\n      "effect": "poison"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "闇夜の暗殺者クロウ"\n  }\n}', NULL, '2026-07-04 04:37:03', '2026-07-04 04:37:50');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (11, 1, 2, 'completed', 'teamA', 3, '雷光の忍者リョウ', 'サンプルデッキAは炎の剣士、氷魔術、雷忍者、岩巨人の四体で構成され、攻撃力と防御力のバランスが取れた多彩な構成である。', 'サンプルデッキBは重装甲重戦車、高速機械狼、深海触手魔物、砂漠の狂戦士の四体で構成され、高攻撃・低防御の個性的な配分が特徴である。', 'teamA', '{\n  "analysis": {\n    "teamA": "サンプルデッキAは炎の剣士、氷魔術、雷忍者、岩巨人の四体で構成され、攻撃力と防御力のバランスが取れた多彩な構成である。",\n    "teamB": "サンプルデッキBは重装甲重戦車、高速機械狼、深海触手魔物、砂漠の狂戦士の四体で構成され、高攻撃・低防御の個性的な配分が特徴である。",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "Turn 1: 鋼鉄の重戦車ゴライアスが主砲斉射を放ち、チームA全員に金属の雨のような大ダメージを与える！"\n    },\n    {\n      "turn": 2,\n      "message": "Turn 2: 紅蓮の剣士アレンが炎の斬撃で砂漠の狂戦士ハディードに火の粉を吹き付け、体力を削る！"\n    },\n    {\n      "turn": 3,\n      "message": "Turn 3: 氷結の魔女セレナが絶対零度で疾走する機械獣メカウルフを凍りつかせ、動きを封じる！"\n    },\n    {\n      "turn": 4,\n      "message": "Turn 4: 砂漠の狂戦士ハディードが砂塵の乱舞で大地の巨人ドルグに砂嵐を巻き付け、防御を低下させる！"\n    },\n    {\n      "turn": 5,\n      "message": "Turn 5: 雷光の忍者リョウが雷閃刃を放ち、砂漠の狂戦士ハディードに猛き一撃！ハディードは戦闘不能に！"\n    },\n    {\n      "turn": 6,\n      "message": "Turn 6: 深海の魔物クラーケンが触手絡めで大地の巨人ドルグを締め付け、動作不能に！"\n    },\n    {\n      "turn": 7,\n      "message": "Turn 7: 防御不能となったドルグの代わりに、疾風の弓使いエリカが支援に配置！エリカが疾風連射で重戦車ゴライアスに矢を雨降りさせる！"\n    },\n    {\n      "turn": 8,\n      "message": "Turn 8: 残るTeam Bの重戦車ゴライアスは致命的なダメージを受け、倒れる！チームAの全ユニットが勝利！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "metal"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "雷光の忍者リョウ",\n      "effect": "lightning"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "bind"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "雷光の忍者リョウ"\n  }\n}', NULL, '2026-07-04 04:49:51', '2026-07-04 04:50:14');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (12, 1, 2, 'pending', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-07-04 04:50:59', NULL);
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (13, 1, 2, 'completed', 'teamA', 1, '紅蓮の剣士アレン', 'チームAは火・氷・雷と多彩な属性と自己回復、防御力の高い巨人が揃い、凍結や自己回復で持続力に優れる。一方防御が高いが素早さが低いTeamBは重装兵器と連続砂塵攻撃で大破壊を狙えるが、回復手段が少ない。バランスと汎用性でTeamAがやや上回ると予測。', 'チームBは防御力とburst damageに特化した重戦車と狂戦士が強いが、回復やステータス付与が希薄で、多様な属性や奇襲が少ない。持続戦闘では劣る可能性がある。', 'teamA', '{\n  "analysis": {\n    "teamA": "チームAは火・氷・雷と多彩な属性と自己回復、防御力の高い巨人が揃い、凍結や自己回復で持続力に優れる。一方防御が高いが素早さが低いTeamBは重装兵器と連続砂塵攻撃で大破壊を狙えるが、回復手段が少ない。バランスと汎用性でTeamAがやや上回ると予測。",\n    "teamB": "チームBは防御力とburst damageに特化した重戦車と狂戦士が強いが、回復やステータス付与が希薄で、多様な属性や奇襲が少ない。持続戦闘では劣る可能性がある。",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "【Team A】紅蓮の剣士アレンが『紅蓮斬』で鋼鉄の重戦車ゴライアスに燃える剣撃を叩き込み、炎の閃光が走り抜ける！"\n    },\n    {\n      "turn": 2,\n      "message": "【Team B】鋼鉄の重戦車ゴライアスは『装甲展開』を発動し、鋼の防御膜を張り上げて一時的に防御力を上げる！"\n    },\n    {\n      "turn": 3,\n      "message": "【Team B】疾走する機械獣メカウルフが『超音速タックル』で雷光の忍者リョウに突撃、轟音とともに体が吹き飛ぶ！"\n    },\n    {\n      "turn": 4,\n      "message": "【Team A】氷結の魔女セレナが『絶対零度』を放ち、全敵を凍りつかせて行動不能に近い状態に陥れた！世界が凍りつく！"\n    },\n    {\n      "turn": 5,\n      "message": "【Team A】大地の巨人ドルグが『大地割断』で地面を叩き割り、衝撃波がクラーケンに直撃！大地が唸りを上げる！"\n    },\n    {\n      "turn": 6,\n      "message": "【Team B】砂漠の狂戦士ハディードが『砂塵の乱舞』で砂嵐と刃を同時に解き放ち、エリカに連続ダメージを与える！"\n    },\n    {\n      "turn": 7,\n      "message": "【Team A】紅蓮の剣士アレンが再び『紅蓮斬』でゴライアスの防御を突き破り、最後に『不死鳥の舞』で体力を回復、敵の意気を完全に沈めた！"\n    },\n    {\n      "turn": 8,\n      "message": "【Result】Team Bの前衛全員が戦闘不能に！Team Aの勝利とともに熱戦が幕を閉じる！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "shield"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "impact"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "earth"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sand"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', NULL, '2026-07-04 04:53:18', '2026-07-04 04:53:53');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (14, 1, 2, 'completed', 'teamA', 1, '紅蓮の剣士アレン', '前衛は炎の剣士、氷魔法、雷忍者、岩巨人。支援は風弓、闇討ち、光騎士、毒術師。多彩な能力と高い攻撃力が特徴。', '前衛は重装戦車、高速機械狼、深海触手、砂漠の狂戦士。支援は月光巫女、炎竜、氷狼、空剣聖。高防御と強力な範囲攻撃が強み。', 'teamA', '{\n  "analysis": {\n    "teamA": "前衛は炎の剣士、氷魔法、雷忍者、岩巨人。支援は風弓、闇討ち、光騎士、毒術師。多彩な能力と高い攻撃力が特徴。",\n    "teamB": "前衛は重装戦車、高速機械狼、深海触手、砂漠の狂戦士。支援は月光巫女、炎竜、氷狼、空剣聖。高防御と強力な範囲攻撃が強み。",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "紅蓮の剣士アレン が 紅蓮斬 を使用し、鋼鉄の重戦車ゴライアス に 1 のダメージ！ (HP 15→14)"\n    },\n    {\n      "turn": 2,\n      "message": "鋼鉄の重戦車ゴライアス が 主砲斉射 を使用し、全敵に 1 のダメージ！ (アレン HP 19, セレナ HP 19, リョウ HP 14, ドルグ HP 24)"\n    },\n    {\n      "turn": 3,\n      "message": "氷結の魔女セレナ が 絶対零度 を使用し、全敵に 1 のダメージ！ (ゴライアス HP 13, 疾走する機械獣メカウルフ HP 9, 深海の魔物クラーケン HP 29, 砂漠の狂戦士ハディード HP 14)"\n    },\n    {\n      "turn": 4,\n      "message": "疾走する機械獣メカウルフ が 超音速タックル を使用し、雷光の忍者リョウ を攻撃！ リョウ の体力 14 → 0 (撃沈!)"\n    },\n    {\n      "turn": 5,\n      "message": "前衛の雷光の忍者リョウ が 行動不能に！ 闇夜の暗殺者クロウ が 前衛へ補充されました。"\n    },\n    {\n      "turn": 6,\n      "message": "聖光の騎士アルフレッド が 聖光の裁き を使用し、深海の魔物クラーケン に 3 のダメージ！ (HP 29→26)"\n    },\n    {\n      "turn": 7,\n      "message": "砂漠の狂戦士ハディード が 砂塵の乱舞 を使用し、全敵に 1 のダメージ！ (アレン HP 18, セレナ HP 18, アルフレッド HP 19, ドルグ HP 23)"\n    },\n    {\n      "turn": 8,\n      "message": "深海の魔物クラーケン が 触手絡め を使用し、大地の巨人ドルグ を拘束し行動不能に！"\n    },\n    {\n      "turn": 9,\n      "message": "前衛の大地の巨人ドルグ が 行動不能に！ 毒霧の暗黒術士ヴェノム が 前衛へ補充されました。"\n    },\n    {\n      "turn": 10,\n      "message": "鋼鉄の重戦車ゴライアス が 装甲展開 を使用し、防御力が上昇！"\n    },\n    {\n      "turn": 11,\n      "message": "氷結の魔女セレナ が 絶対零度 を使用し、鋼鉄の重戦車ゴライアス に 1 のダメージ！ (HP 12→11)"\n    },\n    {\n      "turn": 12,\n      "message": "月光の巫女ルナ が 月光浄化 を使用し、聖光の騎士アルフレッド に 1 のダメージ！ (HP 20→19)"\n    },\n    {\n      "turn": 13,\n      "message": "業火の竜人イグニス が 滅焦竜炎 を使用し、紅蓮の剣士アレン を炎で焼き尽くす！ (HP 18→0) (撃沈!)"\n    },\n    {\n      "turn": 14,\n      "message": "前衛の紅蓮の剣士アレン が 行動不能に！ 疾風の弓使いエリカ が 前衛へ補充されました。"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "cannon"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "impact"\n    },\n    {\n      "type": "special_move",\n      "character": "聖光の騎士アルフレッド",\n      "effect": "light"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sand"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "bind"\n    },\n    {\n      "type": "special_move",\n      "character": "業火の竜人イグニス",\n      "effect": "fire"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', NULL, '2026-07-04 04:54:37', '2026-07-04 04:55:47');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (15, 1, 2, 'completed', 'teamB', 12, '砂漠の狂戦士ハディード', 'サンプルデッキA', 'サンプルデッキB', 'teamB', '{\n  "analysis": {\n    "teamA": "サンプルデッキA",\n    "teamB": "サンプルデッキB",\n    "predictedWinner": "teamB"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "雷光の忍者リョウが雷閃刃で鋼鉄の重戦車ゴライアスに雷光一閃、命中！"\n    },\n    {\n      "turn": 2,\n      "message": "砂漠の狂戦士ハディードが砂塵の乱舞で紅蓮の剣士アレンに砂嵐と共に刃が乱舞、倒した！"\n    },\n    {\n      "turn": 3,\n      "message": "深海の魔物クラーケンが触手絡めで大地の巨人ドルグを締め上げ、行動を封じた！"\n    },\n    {\n      "turn": 4,\n      "message": "大地の巨人ドルグが大地割断で深海の魔物クラーケンに地震の力を叩き込み、体力を削った！"\n    },\n    {\n      "turn": 5,\n      "message": "砂漠の狂戦士ハディードが砂塵の乱舞で大地の巨人ドルグに砂嵐を呼び、倒した！"\n    },\n    {\n      "turn": 6,\n      "message": "雷光の忍者リョウが雷閃刃で深海の魔物クラーケンに雷光一閃、倒した！"\n    },\n    {\n      "turn": 7,\n      "message": "砂漠の狂戦士ハディードが砂塵の乱舞で雷光の忍者リョウに砂嵐を叩きつけ、倒した！"\n    },\n    {\n      "turn": 8,\n      "message": "氷結の魔女セレナが絶対零度で砂漠の狂戦士ハディードを凍りつかせ、行動を封じた！"\n    },\n    {\n      "turn": 9,\n      "message": "砂漠の狂戦士ハディードが砂塵の乱舞で氷結の魔女セレナに砂嵐を叩き込み、倒した！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "雷光の忍者リョウ",\n      "effect": "lightning"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sandstorm"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "bind"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "earthquake"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sandstorm"\n    },\n    {\n      "type": "special_move",\n      "character": "雷光の忍者リョウ",\n      "effect": "lightning"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sandstorm"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "freeze"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sandstorm"\n    }\n  ],\n  "result": {\n    "winner": "teamB",\n    "mvp": "砂漠の狂戦士ハディード"\n  }\n}', NULL, '2026-07-04 05:06:24', '2026-07-04 05:07:12');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (16, 1, 2, 'completed', 'teamA', 1, '紅蓮の剣士アレン', 'サンプルデッキAは、炎の剣士、氷魔術、雷速忍者、岩の巨人という多彩な前衛陣営を擁し、速さと多彩な必殺技で不利な相手でも柔軟に対応できるバランスを持つ。一方、チームBは重装甲の重戦車や高火力の狂戦士を中心に、防御や連続攻撃に特化した布陣だが、速さと多様性に欠けるため、単体の特化が弱点である', 'サンプルデッキBは、鋼鉄の重戦車、高速機械獣、深海の触手魔物、砂漠の狂戦士という四体の前衛で構成され、防御力と火力に強いが、全体の速さと回復手段が弱く、多彩な_elem_攻撃に弱い構造である', 'teamA', '{\n  "analysis": {\n    "teamA": "サンプルデッキAは、炎の剣士、氷魔術、雷速忍者、岩の巨人という多彩な前衛陣営を擁し、速さと多彩な必殺技で不利な相手でも柔軟に対応できるバランスを持つ。一方、チームBは重装甲の重戦車や高火力の狂戦士を中心に、防御や連続攻撃に特化した布陣だが、速さと多様性に欠けるため、単体の特化が弱点である",\n    "teamB": "サンプルデッキBは、鋼鉄の重戦車、高速機械獣、深海の触手魔物、砂漠の狂戦士という四体の前衛で構成され、防御力と火力に強いが、全体の速さと回復手段が弱く、多彩な_elem_攻撃に弱い構造である",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "【激闘開始】Team Aの紅蓮の剣士アレンが炎の刀を振り上げ、「紅蓮斬」を敢行！炎の斬撃が闇を切り裂く――敵陣に燃えさかる光が走る！"\n    },\n    {\n      "turn": 2,\n      "message": "Team Bの重装甲重戦車ゴライアスは金属音を鳴らし、「主砲斉射」を放つ！鋼鉄の雷が轟き、前衛全体に直撃する！"\n    },\n    {\n      "turn": 3,\n      "message": "Team Aの氷結の魔女セレナは凍りつく瞳で「絶対零度」を呼び出す！世界が氷漬けになり、敵の動きが一瞬凍り付く！"\n    },\n    {\n      "turn": 4,\n      "message": "Team Bの疾走する機械獣メカウルフは音速の突進で「超音速タックル」！轟音とともに前列の雷光の忍者リョウを襲い、体が崩れる！"\n    },\n    {\n      "turn": 5,\n      "message": "Team Aの雷光の忍者リョウは残りの体力で「雷閃刃」を発動！光速の斬撃が疾走する機械獣を切り裂き、閃光が走る！"\n    },\n    {\n      "turn": 6,\n      "message": "Team Bの深海の魔物クラーケンは触手を浮かび上がらせ「触手絡め」！闇の底から伸びた触手がドルグの足元を締め付け、動きを封じる！"\n    },\n    {\n      "turn": 7,\n      "message": "Team Aの岩の巨人ドルグは地面を叩き上げ「大地割断」！大地が唸り、触手が揺らぎ、敵の防御が崩れ落ちる！"\n    },\n    {\n      "turn": 8,\n      "message": "最終的にチームBの全前衛が次々に戦闘不能に！最後の砂漠の狂戦士ハディードさえも氷と雷の連続攻撃で倒れ、激闘はTeam Aの勝利に幕を閉じる！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "steel"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "shock"\n    },\n    {\n      "type": "special_move",\n      "character": "雷光の忍者リョウ",\n      "effect": "lightning"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "earthquake"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', NULL, '2026-07-04 05:11:08', '2026-07-04 05:11:55');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (17, 1, 2, 'completed', 'teamB', 6, '闇夜の暗殺者クロウ', '前衛は紅蓮の剣士アレン、氷結の魔女セレナ、雷光の忍者リョウ、大地の巨人ドルグ。控えに弓手エリカ、暗殺者クロウ、騎士アルフレッド、術士ヴェノムを抱える。攻守バランスは悪く、防御が低め。', '前衛は鋼鉄の重戦車ゴрайas、疾走する機械獣メカウルフ、深海の魔物クラーケン、砂漠の狂戦士ハディード。控えに巫女ルナ、竜人イグニス、狼フェンリル、剣聖ゼファーを抱える。防御力が高く、攻撃力も豊富。', 'teamB', '{\n  "analysis": {\n    "teamA": "前衛は紅蓮の剣士アレン、氷結の魔女セレナ、雷光の忍者リョウ、大地の巨人ドルグ。控えに弓手エリカ、暗殺者クロウ、騎士アルフレッド、術士ヴェノムを抱える。攻守バランスは悪く、防御が低め。",\n    "teamB": "前衛は鋼鉄の重戦車ゴрайas、疾走する機械獣メカウルフ、深海の魔物クラーケン、砂漠の狂戦士ハディード。控えに巫女ルナ、竜人イグニス、狼フェンリル、剣聖ゼファーを抱える。防御力が高く、攻撃力も豊富。",\n    "predictedWinner": "teamB"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "戦闘開始！紅蓮の剣士アレンが「紅蓮斬」で鋼鉄の重戦車ゴрайasに炎の斬撃を放つ。"\n    },\n    {\n      "turn": 2,\n      "message": "疾走する機械獣メカウルフが「超音速タックル」で雷光の忍者リョウに突撃し、リョウは戦闘不能に。"\n    },\n    {\n      "turn": 3,\n      "message": "氷結の魔女セレナが「絶対零度」で深海の魔物クラーケンを凍らせ、行動を封じる。"\n    },\n    {\n      "turn": 4,\n      "message": "深海の魔物クラーケンが「触手絡め」で大地の巨人ドルグを締め付け、動きを止める。"\n    },\n    {\n      "turn": 5,\n      "message": "砂漠の狂戦士ハディードが「砂塵の乱舞」で紅蓮の剣士アレンに膭波を叩き込み、アレンは倒れる。"\n    },\n    {\n      "turn": 6,\n      "message": "残った前衛メンバーの復活として、闇夜の暗殺者クロウがランダムで補充され、チームAに 새 frontunit が加入。"\n    },\n    {\n      "turn": 7,\n      "message": "闇夜の暗殺者クロウが「闇討ちの一閃」で鋼鉄の重戦車ゴraïasに致命的な一撃を与え、ゴraïasは戦闘不能に。"\n    },\n    {\n      "turn": 8,\n      "message": "聖光の騎士アルフレッドが「守護の誓い」で味方の防御を上げ、逆転の兆しを見せるが、クラーケンの「深海の咆哮」で命中率が低下。"\n    },\n    {\n      "turn": 9,\n      "message": "疾風の弓使いエリカが「疾風連射」で砂漠の狂戦士ハディードに連続矢を放ち、ハディードを倒す。"\n    },\n    {\n      "turn": 10,\n      "message": "大地の巨人ドルグが「大地割断」で機械獣メカウルフに衝撃波を叩き込み、メカウルフは戦闘不能に。"\n    },\n    {\n      "turn": 11,\n      "message": "チームAの全前衛ユニットが次々に壊滅し、チームBが勝利を確定。"\n    },\n    {\n      "turn": 12,\n      "message": "MVPは闇夜の暗殺者クロウ！奇襲の一撃で勝負を変えた。"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "bind"\n    },\n    {\n      "type": "special_move",\n      "character": "闇夜の暗殺者クロウ",\n      "effect": "critical"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sandstorm"\n    }\n  ],\n  "result": {\n    "winner": "teamB",\n    "mvp": "闇夜の暗殺者クロウ"\n  }\n}', NULL, '2026-07-04 05:15:32', '2026-07-04 05:15:50');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (18, 1, 2, 'completed', 'teamB', 14, '業火の竜人イグニス', 'サンプルデッキA', 'サンプルデッキB', 'teamB', '{\n  "analysis": {\n    "teamA": "サンプルデッキA",\n    "teamB": "サンプルデッキB",\n    "predictedWinner": "teamB"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "紅蓮の剣士アレンが「紅蓮斬」を使用し、鋼鉄の重戦車ゴライアスに炎の斬撃が炸裂！"\n    },\n    {\n      "turn": 2,\n      "message": "疾走する機械獣メカウルフが「超音速タックル」で紅蓮の剣士アレンを倒した！"\n    },\n    {\n      "turn": 3,\n      "message": "深海の魔物クラーケンが「触手絡め」で大地の巨人ドルグを締め上げた！"\n    },\n    {\n      "turn": 4,\n      "message": "氷結の魔女セレナが「絶対零度」で深海の魔物クラーケンを凍りつかせた！"\n    },\n    {\n      "turn": 5,\n      "message": "鋼鉄の重戦車ゴライアスが「主砲斉射」で雷光の忍者リョウを炸裂させた！"\n    },\n    {\n      "turn": 6,\n      "message": "砂漠の狂戦士ハディードが「砂塵の乱舞」で疾風の弓使いエリカを襲った！"\n    },\n    {\n      "turn": 7,\n      "message": "大地の巨人が「大地割断」で砂漠の狂戦士ハディードを叩き砕いた！"\n    },\n    {\n      "turn": 8,\n      "message": "疾走する機械獣メカウルフが「超音速タックル」で大地の巨人ドルグを倒した！"\n    },\n    {\n      "turn": 9,\n      "message": "鋼鉄の重戦車ゴライアスが「装甲展開」で防御力を高めた！"\n    },\n    {\n      "turn": 10,\n      "message": "深海の魔物クラーケンが「深海の咆哮」で闇夜の暗殺者クロウを威圧した！"\n    },\n    {\n      "turn": 11,\n      "message": "聖光の騎士アルフレッドが「聖光の裁き」で鋼鉄の重戦車ゴライアスを撃破した！"\n    },\n    {\n      "turn": 12,\n      "message": "闇夜の暗殺者クロウが「闇討ちの一閃」で深海の魔物クラーケンを貫いた！"\n    },\n    {\n      "turn": 13,\n      "message": "業火の竜人イグニスが「滅焦竜炎」で氷結の魔女セレナを焼き尽くした！"\n    },\n    {\n      "turn": 14,\n      "message": "疾走する機械獣メカウルフが「超音速タックル」で闇夜の暗殺者クロウを倒した！"\n    },\n    {\n      "turn": 15,\n      "message": "聖光の騎士アルフレッドが「聖光の裁き」で疾走する機械獣メカウルフを撃破した！"\n    },\n    {\n      "turn": 16,\n      "message": "月光の巫女ルナが「月光浄化」で毒霧の暗黒術士ヴェノムを浄化した！"\n    },\n    {\n      "turn": 17,\n      "message": "業火の竜人イグニスが「滅焦竜炎」で聖光の騎士アルフレッドを炎上させた！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "impact"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "bind"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "energy"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sand"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "earth"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "impact"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "defense"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "roar"\n    },\n    {\n      "type": "special_move",\n      "character": "聖光の騎士アルフレッド",\n      "effect": "light"\n    },\n    {\n      "type": "special_move",\n      "character": "闇夜の暗殺者クロウ",\n      "effect": "dark"\n    },\n    {\n      "type": "special_move",\n      "character": "業火の竜人イグニス",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "impact"\n    },\n    {\n      "type": "special_move",\n      "character": "聖光の騎士アルフレッド",\n      "effect": "light"\n    },\n    {\n      "type": "special_move",\n      "character": "月光の巫女ルナ",\n      "effect": "light"\n    },\n    {\n      "type": "special_move",\n      "character": "業火の竜人イグニス",\n      "effect": "fire"\n    }\n  ],\n  "result": {\n    "winner": "teamB",\n    "mvp": "業火の竜人イグニス"\n  }\n}', NULL, '2026-07-04 05:16:51', '2026-07-04 05:17:57');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (20, 1, 2, 'completed', 'teamA', 1, '紅蓮の剣士アレン', 'Team Aは炎・氷・雷・大地の四属性を持つ多様な前衛と支援キャラを持ち、幅広い戦術が可能。バランスと柔軟性が強みである。', 'Team Bは重防御と高攻撃・高速を併せ持つ硬い前衛で構成。特定の属性に弱点はあるものの、耐久力と单体の攻撃力が高い。', 'teamA', '{\n  "analysis": {\n    "teamA": "Team Aは炎・氷・雷・大地の四属性を持つ多様な前衛と支援キャラを持ち、幅広い戦術が可能。バランスと柔軟性が強みである。",\n    "teamB": "Team Bは重防御と高攻撃・高速を併せ持つ硬い前衛で構成。特定の属性に弱点はあるものの、耐久力と单体の攻撃力が高い。",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "第1ターン：紅蓮の剣士アレンがゴライアスに 紅蓮斬 を使用しゴライアスが戦闘不能になった。鋼鉄の重戦車ゴライアスが主砲斉射を使用したがしばらく後に疾走する機械獣メカウルフが超音速タックルでセレナが戦闘不能になった。氷結の魔女セレナが絶対零度を使用したがすぐに大地の巨人ドルグが大地割断を使用しクラーケンとハディードに衝撃を与えクラーケンが戦闘不能になった。闇夜の暗殺者クロウが闇討ちの一閃でリョウに決定的ダメージを与えリョウが戦闘不能になった。残りのドルグが砂塵の乱舞によりハディードに決定的ダメージを与えハディードが戦闘不能になった。Team B全員が前衛で戦闘不能となりTeam Aの勝利が決定。"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "steel"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "sound"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "深海の魔物クラーケン",\n      "effect": "bind"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sand"\n    },\n    {\n      "type": "special_move",\n      "character": "闇夜の暗殺者クロウ",\n      "effect": "dark"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "earth"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', NULL, '2026-07-04 05:27:50', '2026-07-04 05:28:16');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (21, 1, 2, 'completed', 'teamA', 1, '紅蓮の剣士アレン', 'チームAは炎と氷、雷、土の多彩な前衛ユニットと回復・防御支援を備え、多段階のデバフと瞬撃で相手を圧倒しやすい構成だ。', 'チームBは圧倒的攻撃力と防御力を持つ重装備ユニットが中心だが、速度と回復能力に乏しく、凍結・毒・砂嵐といったデバフに弱いリスクを抱えていた。', 'teamA', '{\n  "analysis": {\n    "teamA": "チームAは炎と氷、雷、土の多彩な前衛ユニットと回復・防御支援を備え、多段階のデバフと瞬撃で相手を圧倒しやすい構成だ。",\n    "teamB": "チームBは圧倒的攻撃力と防御力を持つ重装備ユニットが中心だが、速度と回復能力に乏しく、凍結・毒・砂嵐といったデバフに弱いリスクを抱えていた。",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "紅蓮の剣士アレンが炎の刀で『紅蓮斬』を放ち、鋼鉄の重戦車ゴライアスの装甲を切り裂く！燃えるような斬撃が鋼の壁に突き刺さった！"\n    },\n    {\n      "turn": 2,\n      "message": "砂漠の狂戦士ハディードが砂嵐と刀を同時に舞い踊る『砂塵の乱舞』で、氷結の魔女セレナと雷光の忍者リョウに砂の刃が命中し、体力を削った！"\n    },\n    {\n      "turn": 3,\n      "message": "氷結の魔女セレナが凍りつく大地から『絶対零度』を呼び寄せ、疾走する機械獣メカウルフの足を氷で締め付け、動きを封じた！"\n    },\n    {\n      "turn": 4,\n      "message": "雷光の忍者リョウが光速の一閃で『雷閃刃』を放ち、砂漠の狂戦士ハディードの胸部を貫く！砂漠の狂戦士ハディードが戦闘不能になった"\n    },\n    {\n      "turn": 5,\n      "message": "紅蓮の剣士アレンが再び炎の刀で『紅蓮斬』を放ち、鋼鉄の重戦車ゴライアスの胸部を貫く！鋼鉄の重戦車ゴライアスが戦闘不能になった"\n    },\n    {\n      "turn": 6,\n      "message": "大地の巨人ドルグが拳で『大地割断』を叩き込み、深海の魔物クラーケンの触手を砕き、深海の魔物クラーケンが戦闘不能になった"\n    },\n    {\n      "turn": 7,\n      "message": "疾走する機械獣メカウルフが凍結と衝撃で消滅し、疾走する機械獣メカウルフが戦闘不能になった"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "sand"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "雷光の忍者リョウ",\n      "effect": "lightning"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "earth"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', NULL, '2026-07-04 05:30:04', '2026-07-04 05:31:18');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (23, 1, 2, 'completed', 'teamB', NULL, '鋼鉄の重戦車ゴрайás', 'サンプルデッキA', 'サンプルデッキB', 'teamB', '{\n  "analysis": {\n    "teamA": "サンプルデッキA",\n    "teamB": "サンプルデッキB",\n    "predictedWinner": "teamB"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "戦闘開始！ 紅蓮の剣士アレンが必殺技『紅蓮斬』を発動し、鋼鉄の重戦車ゴрайásに炎の斬撃を叩き込んだ。続く鋼鉄の重戦車ゴрайásは必殺技『主砲斉射』を発動し、チームA全体に砲撃を放った。氷結の魔女セレナは必殺技『絶対零度』を発動し、深海の魔物クラーケンを凍りつかせた。雷光の忍者リョウは必殺技『雷閃刃』を発動し、疾走する機械獣メカウルフに雷光一閃を食らわせた。"\n    },\n    {\n      "turn": 2,\n      "message": "大地の巨人ドルグが必殺技『不死鳥の舞』を発動し、体力を回復しながら反撃態勢に入った。闇夜の暗殺者クロウは必殺技『闇討ちの一閃』を発動し、遠距離から突如として襲撃を仕掛けた。"\n    },\n    {\n      "turn": 3,\n      "message": "聖光の騎士アルフレッドが必殺技『聖光の裁き』を発動し、ドルグに大ダメージを与えた。"\n    },\n    {\n      "turn": 4,\n      "message": "深海の魔物クラーケンが戦闘不能になった。闇夜の暗殺者クロウが代わりに前衛へ補充された。"\n    },\n    {\n      "turn": 5,\n      "message": "雷光の忍者リョウが必殺技『雷閃刃』を再び発動し、残りの前衛を次々と倒した。"\n    },\n    {\n      "turn": 6,\n      "message": "チームA全員が戦闘不能になった。チームBの勝利だ！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴрайás",\n      "effect": "steel"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "雷光の忍者リョウ",\n      "effect": "lightning"\n    },\n    {\n      "type": "special_move",\n      "character": "大地の巨人ドルグ",\n      "effect": "revive"\n    },\n    {\n      "type": "special_move",\n      "character": "闇夜の暗殺者クロウ",\n      "effect": "assassin"\n    },\n    {\n      "type": "special_move",\n      "character": "聖光の騎士アルフレッド",\n      "effect": "light"\n    }\n  ],\n  "result": {\n    "winner": "teamB",\n    "mvp": "鋼鉄の重戦車ゴрайás"\n  }\n}', NULL, '2026-07-04 05:46:29', '2026-07-04 05:46:57');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (29, 1, 4, 'completed', 'teamA', 1, '紅蓮の剣士アレン', 'Team Aは紅蓮・氷結・雷光・大地と四者四様の得意分野を持つ、パラメータの大半を攻撃・防御・素早さ・体力に集中投資した生粋の戦闘集団。無駄のないステータス配分により、総合的な戦闘力は高い。', 'Team Bはフットサルをモチーフにしたチームワーク重視の面々で、キック力やパワーなど一部は高い数値を誇るものの、料理・音楽センス・レア出現度・やさしさといった非戦闘的な資質にもポイントを割いており、純粋な戦闘力では見劣りする。', 'teamA', '{\n  "analysis": {\n    "teamA": "Team Aは紅蓮・氷結・雷光・大地と四者四様の得意分野を持つ、パラメータの大半を攻撃・防御・素早さ・体力に集中投資した生粋の戦闘集団。無駄のないステータス配分により、総合的な戦闘力は高い。",\n    "teamB": "Team Bはフットサルをモチーフにしたチームワーク重視の面々で、キック力やパワーなど一部は高い数値を誇るものの、料理・音楽センス・レア出現度・やさしさといった非戦闘的な資質にもポイントを割いており、純粋な戦闘力では見劣りする。",\n    "predictedWinner": "teamA"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "戦闘開始！ 行動順はランダムに決定された。センゴクンが通常攻撃で紅蓮の剣士アレンに強烈なキックを叩き込んだ。防御の低いアレンは大きくよろめいた。氷結の魔女セレナは通常攻撃でシライに冷気弾を放った。イワルンはすばやい身のこなしで雷光の忍者リョウの攻撃をかわしつつ体当たりを返した。"\n    },\n    {\n      "turn": 2,\n      "message": "シライが必殺技『ストロングウォーク』を発動し、仲間の体力を回復しながら味方全体の防御力を2段階上げた。チームあしたばの前衛が硬くなった。"\n    },\n    {\n      "turn": 3,\n      "message": "紅蓮の剣士アレンが必殺技『紅蓮斬』を発動し、シライに炎の斬撃を放った。防御力が上がっていたシライだったが、それでも大きく怯んだ。"\n    },\n    {\n      "turn": 4,\n      "message": "センゴクンが必殺技『レア・エンカウント・キャノン』を発動し、大地の巨人ドルグへ重力をねじ曲げるほどのエネルギー弾を撃ち込んだ。高い防御力を誇るドルグは何とか耐えきったが、素早さが低くまともに直撃を受けてしまった。"\n    },\n    {\n      "turn": 5,\n      "message": "雷光の忍者リョウが必殺技『雷閃刃』を発動し、タシロップに雷速の斬撃を放った。ドリブルとリーチに特化し打たれ弱いタシロップは受け止めきれず、タシロップが戦闘不能になった。タニョンが代わりに前衛へ補充された。"\n    },\n    {\n      "turn": 6,\n      "message": "イワルンが必殺技『クレバー・スピード』を発動し、相手の動きを完璧に予測して氷結の魔女セレナへ回り込みながら体当たりを見舞った。魔力に特化し防御が薄いセレナは大きくよろめいた。"\n    },\n    {\n      "turn": 7,\n      "message": "氷結の魔女セレナが必殺技『絶対零度』を発動し、チームあしたばの前衛全体を凍りつかせた。動きを封じられたイワルンとタニョンは反撃もままならず苦しんだ。"\n    },\n    {\n      "turn": 8,\n      "message": "センゴクンが必殺技『ルーティン・バースト』を再び発動し、雷光の忍者リョウへ超重量級の体当たりを浴びせた。素早さに極振りし防御が低いリョウは耐えきれず、雷光の忍者リョウが戦闘不能になった。闇夜の暗殺者クロウが代わりに前衛へ補充された。"\n    },\n    {\n      "turn": 9,\n      "message": "闇夜の暗殺者クロウが必殺技『闇討ちの一閃』を発動し、隙を見せたセンゴクンの急所を貫いた。持続力はあっても奇襲に弱いセンゴクンは大ダメージを受け、センゴクンが戦闘不能になった。ネギルじいが代わりに前衛へ補充された。同じ頃、大地の巨人ドルグの拳を受け続けたシライも力尽き、シライが戦闘不能になった。カネマールが代わりに前衛へ補充された。"\n    },\n    {\n      "turn": 10,\n      "message": "紅蓮の剣士アレンが必殺技『紅蓮斬』を再び発動し、残る前衛のイワルン・タニョン・ネギルじい・カネマールへ次々と炎の斬撃を浴びせた。戦闘向きの耐久力を持たない面々は耐えきれず、イワルン、タニョン、ネギルじい、カネマールが戦闘不能になった。チームあしたば全員が戦闘不能になった。チームAの勝利だ！"\n    }\n  ],\n  "events": [\n    {\n      "type": "normal_attack",\n      "character": "センゴクン",\n      "effect": "kick"\n    },\n    {\n      "type": "normal_attack",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "シライ",\n      "effect": "guard_up"\n    },\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    },\n    {\n      "type": "special_move",\n      "character": "センゴクン",\n      "effect": "gravity"\n    },\n    {\n      "type": "special_move",\n      "character": "雷光の忍者リョウ",\n      "effect": "lightning"\n    },\n    {\n      "type": "special_move",\n      "character": "イワルン",\n      "effect": "speed"\n    },\n    {\n      "type": "special_move",\n      "character": "氷結の魔女セレナ",\n      "effect": "ice"\n    },\n    {\n      "type": "special_move",\n      "character": "センゴクン",\n      "effect": "impact"\n    },\n    {\n      "type": "special_move",\n      "character": "闇夜の暗殺者クロウ",\n      "effect": "assassin"\n    },\n    {\n      "type": "special_move",\n      "character": "紅蓮の剣士アレン",\n      "effect": "fire"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "紅蓮の剣士アレン"\n  }\n}', '429 Rate limit exceeded: free-models-per-day. Add 10 credits to unlock 1000 free model requests per day', '2026-07-04 12:03:33', '2026-07-04 12:10:36');
INSERT INTO battles (id, deck_a_id, deck_b_id, status, winner, mvp_character_id, mvp_name, analysis_team_a, analysis_team_b, predicted_winner, raw_ai_response, error_message, created_at, completed_at) VALUES (30, 2, 4, 'completed', 'teamA', 9, '鋼鉄の重戦車ゴライアス', 'Team Aは重装甲と突撃力を持つが、速度と支援能力に欠ける。', 'Team Bは多彩なサポートと_control_能力を持ち、柔軟な戦術が可能。', 'teamB', '{\n  "analysis": {\n    "teamA": "Team Aは重装甲と突撃力を持つが、速度と支援能力に欠ける。",\n    "teamB": "Team Bは多彩なサポートと_control_能力を持ち、柔軟な戦術が可能。",\n    "predictedWinner": "teamB"\n  },\n  "battleLog": [\n    {\n      "turn": 1,\n      "message": "鋼鉄の重戦車ゴライアスが必殺技『主砲斉射』を発動し、シライに大ダメージを与えた。"\n    },\n    {\n      "turn": 2,\n      "message": "イワルンが必殺技『万能スターダスト』を発動し、team B全体の防御力を下げる効果を発射した。"\n    },\n    {\n      "turn": 3,\n      "message": "疾走する機械獣メカウルフが必殺技『超音速タックル』を発動し、イワルンが戦闘不能になった。"\n    },\n    {\n      "turn": 4,\n      "message": "タシロップが必殺技『終わりなき美メロ』を発動し、シライが戦闘不能になった。"\n    },\n    {\n      "turn": 5,\n      "message": "砂漠の狂戦士ハディードが必殺技『砂塵の乱舞』を発動し、残る敵に大打撃を与えた。team Aの勝利だ！！"\n    }\n  ],\n  "events": [\n    {\n      "type": "special_move",\n      "character": "鋼鉄の重戦車ゴライアス",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "イワルン",\n      "effect": "defense_down"\n    },\n    {\n      "type": "special_move",\n      "character": "疾走する機械獣メカウルフ",\n      "effect": "damage"\n    },\n    {\n      "type": "special_move",\n      "character": "タシロップ",\n      "effect": "slow"\n    },\n    {\n      "type": "special_move",\n      "character": "砂漠の狂戦士ハディード",\n      "effect": "damage"\n    }\n  ],\n  "result": {\n    "winner": "teamA",\n    "mvp": "鋼鉄の重戦車ゴライアス"\n  }\n}', NULL, '2026-07-05 04:38:43', '2026-07-05 04:39:09');
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (1, 1, 1, 'チームBの砂漠の狂戦士ハディードが砂塵の乱舞を放ち、チームAの紅蓮の剣士アレンに炎の砂嵐を食らわせ、18ポイントのダメージ！体力が2へと激減！', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (2, 1, 2, 'チームBの深海の魔物クラーケンが触手絡めで氷結の魔女セレナの足元を締め付け、5ポイントのダメージと凍結の恐怖を与える！', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (3, 1, 3, 'チームBの鋼鉄の重戦車ゴライアスが主砲斉射で雷光の忍者リョウに直撃、12ポイントの爆撃！体力が3に激減！', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (4, 1, 4, 'チームBの闇夜の暗殺者クロウが闇討ちの一閃で大地の巨人ドルグの弱点を突き、20ポイントの致命的ダメージ！体力が5に激減！', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (5, 1, 5, 'チームBの深海の魔物クラーケンが再び触手絡めで倒れた紅蓮の剣士アレンに決定的一撃、残体力0となり戦闘不能に！', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (6, 1, 6, 'チームBの鋼鉄の重戦車ゴライアスが残された氷結の魔女セレナに主砲斉射を浴みせ、8ポイントのダメージで体力を7に削る！', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (7, 1, 7, 'チームBの砂漠の狂戦士ハディードが再び砂塵の乱舞を放ち、氷結の魔女セレナに10ポイントの連続ダメージ！体力が0に倒れ、チームA全体が戦闘不能となり試合終了！', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (8, 1, 8, '最終的にチームBが勝利！最前線で貢献した『鋼鉄の重戦車ゴライアス』がMVPに輝く！', 7);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (9, 2, 1, '鋼鉄の重戦車ゴライアス (Team B) fires 主砲斉射, blasting all front enemies of Team A with steel thunder.', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (10, 2, 2, '紅蓮の剣士アレン (Team A) counters with 紅蓮斬 on ゴライアス, igniting the armor and reducing its defense.', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (11, 2, 3, '疾走する機械獣メカウルフ (Team B) attempts 超音速タックル on 紅光の忍者リョウ, but the swift strike is dodged.', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (12, 2, 4, '紅光の忍者リョウ (Team A) executes 雷閃刃 on 疾走する機械獣メカウルフ, slicing through its chassis and knocking it out.', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (13, 2, 5, '氷結の魔女セレナ (Team A) chants 絶対零度, freezing all remaining Team B front units in place.', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (14, 2, 6, '大地の巨人ドルグ (Team A) slams the ground with 大地割断, shaking the frozen クラーケン and cracking its icy hide.', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (15, 2, 7, '砂漠の狂戦士ハディード (Team B) is immobilized by the ice and cannot act this turn.', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (16, 2, 8, '闇夜の暗殺者クロウ (Team A) slips into the shadows and strikes with 闇討ちの一閃, eliminating ハディード.', 7);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (17, 2, 9, '業火の竜人イグニス (Team B) tries to unleash 滅焦竜炎 on セレナ, but the frozen state prevents him from channeling fire.', 8);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (18, 2, 10, '聖光の騎士アルフレッド (Team A) raises his shield with 守護の誓い, bolstering defense of his allies.', 9);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (19, 2, 11, '全敵が戦闘不能に追い込まれたため、Team B withdraws; Team A emerges victorious!', 10);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (20, 3, 1, '戦闘開始！ 前衛の紅蓮の剣士アレンが先手を取り、紅蓮斬で深海の魔物クラーケンへ炎の斬撃を放つ。', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (21, 3, 2, '続く疾走する機械獣メカウルフが超音速タックルで大地の巨人ドルグに直撃、しかしドルグの装甲が光り防御力が上がる。', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (22, 3, 3, '氷結の魔女セレナが絶対零度を発動し、クラーケンを凍結させて行動不能に近い状態にする。', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (23, 3, 4, '砂漠の狂戦士ハディードが砂塵の乱舞で雷光の忍者リョウに連続攻撃、リョウは分身の術で回避率を上げる。', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (24, 3, 5, '鋼鉄の重戦車ゴライアスが主砲斉射で前衛全員に大ダメージ、だがドルグが大地割断でゴライアスの足元を崩し、転倒させる。', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (25, 4, 1, '第1ターン！雷光の忍者リョウが「雷閃刃」で疾走する機械獣メカウルフへ直撃！反撃の「超音速タックル」で紅蓮の剣士アレンに衝撃！続いて砂漠の狂戦士ハディードが「砂塵の乱舞」で大地の巨人ドルグを圧迫！ 紅蓮の剣士アレンは「紅蓮斬」で深海の魔物クラーケンの触手を切り裂き、最後に鋼鉄の重戦車ゴライアスが「主砲斉射」で全体に砲撃！', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (26, 4, 2, '第2ターン！氷結の魔女セレナが「絶対零度」で深海の魔物クラーケンを凍結させ、行動不能に！疾風の弓使いエリカが「疾風連射」で砂漠の狂戦士ハディードに連続ダメージ！クラーケンは「触手絡め」でさらなる行動不能！', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (27, 4, 3, '第3ターン！大地の巨人ドルグが「大地割断」でクラーケンの足元を崩し、倒壊させる！ 鋼鉄の重戦車ゴライアスは「装甲展開」で防御を強化するが、すでに致命的なダメージを受けている！', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (28, 4, 4, '第4ターン！紅蓮の剣士アレンが「不死鳥の舞」で自己回復し、疾風の弓使いエリカが「風纏いの矢」で鋼鉄の重戦車ゴライアスに決定的一撃！チームB全勢が戦闘不能となり、チームAの勝利！', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (29, 5, 1, 'team Bの砂漠の狂戦士ハディードが砂塵の乱舞を放ち、紅蓮の剣士アレンに45の連続ダメージ！', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (30, 5, 2, 'team Aの雷光の忍者リョウが雷閃刃で鋼鉄の重戦車ゴライアスに30の直接ダメージ！', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (31, 5, 3, 'team Bの疾走する機械獣メカウルフが超音速タックルで雷光の忍者リョウに32の致命的打撃！', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (32, 5, 4, 'team Aの氷結の魔女セレナが絶対零度で全敵を凍結させ、行動を封じる！', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (33, 5, 5, 'team Bの深海の魔物クラーケンが触手絡めで氷結の魔女セレナを拘束！', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (34, 5, 6, 'team Aの大地の巨人ドルグが大地割断で深海の魔物クラーケンに25のダメージ！', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (35, 5, 7, 'team Bの砂漠の狂戦士ハディードが再び砂塵の乱舞を使用し、大地の巨人ドルグに45のダメージ！', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (36, 5, 8, 'team Bの深海の魔物クラーケンが深海の咆哮で場を揺らすが、ダメージはなし！', 7);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (37, 5, 9, 'team Aの大地の巨人ドルグが大地割断で深海の魔物クラーケンを撃破！', 8);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (38, 5, 10, 'team Bの砂漠の狂戦士ハディードが砂塵の乱舞で大地の巨人ドルグを倒す！', 9);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (39, 5, 11, 'team Aの闇夜の暗殺者クロウが闇討ちの一閃で砂漠の狂戦士ハディードを倒し、勝利！', 10);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (40, 6, 1, '紅蓮の剣士アレンが『紅蓮斬』を使用し、鋼鉄の重戦車ゴライアスを倒した。', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (41, 6, 2, '疾走する機械獣メカウルフが『超音速タックル』で雷光の忍者リョウを倒した。', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (42, 6, 3, '深海の魔物クラーケンが『触手絡め』で大地の巨人ドルグを倒した。', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (43, 6, 4, '砂漠の狂戦士ハディードが『砂塵の乱舞』で疾風の弓使いエリカを倒した。', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (44, 6, 5, '紅蓮の剣士アレンが『不死鳥の舞』で自身を回復した。', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (45, 6, 6, '月光の巫女ルナが『癒しの祈り』で自身を回復した。', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (46, 6, 7, '闇夜の暗殺者クロウが『闇討ちの一閃』で業火の竜人イグニスを倒した。', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (47, 6, 8, '氷雪の狼フェンリルが『氷牙の一撃』で紅蓮の剣士アレンを倒した。', 7);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (48, 6, 9, '氷結の魔女セレナが『絶対零度』で氷雪の狼フェンリルを倒した。', 8);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (49, 6, 10, '聖光の騎士アルフレッドが『聖光の裁き』で月光の巫女ルナを倒した。', 9);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (50, 7, 1, '▶️ 第1ターン！　紅蓮の剣士アレンが炎の刃『紅蓮斬』で鋼鉄の重戦車ゴライアスに10点の炎ダメージ！　続くゴライアスが主砲斉射で炎の剣士に12点の衝撃を返す！', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (51, 7, 2, '▶️ 第2ターン！　氷結の魔女セレナが『絶対零度』で機械獣メカウルフを凍結させ、行動を封じる！　メカウルフは『超音速タックル』で氷結の魔女に17点の打撃を与え、体力を激減させた！', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (52, 7, 3, '▶️ 第3ターン！　雷光の忍者リョウが『雷閃刃』で深海の魔物クラーケンに5点の雷撃！　クラーケンは『触手絡め』でリョウを締め付け、回避率を低下させる！', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (53, 7, 4, '▶️ 第4ターン！　大地の巨人ドルグが『大地割断』で砂漠の狂戦士ハディードを0点に粉砕！　クラーケンが『深海の咆哮』で全体の行動速度を一瞬だけ低下させた！', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (54, 7, 5, '▶️ 第5ターン！　残っていた重戦車ゴライアスが7点の体力で倒れ、前衛全滅！　最後に紅蓮の剣士アレンが残りの敵を炎の刃で粉砕し、チームAの勝利が確定した！', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (55, 8, 1, 'ターン1：チームAの紅蓮の剣士アレンが必殺技『紅蓮斬』を使用しチームBの鋼鉄の重戦車ゴライアスへ炎の斬撃を叩き込む演出：紅蓮の斬撃が闇を切り裂く！', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (56, 8, 2, 'ターン2：チームBの疾走する機械獣メカウルフが必殺技『超音速タックル』でチームAの大地の巨人ドルグへ高速突進し衝撃波で防御を低下させる演出：轟音を置き去りにする一撃が炸裂する！', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (57, 8, 3, 'ターン3：チームAの氷結の魔女セレナが必殺技『絶対零度』でチームBの深海の魔物クラーケン全体を凍りつかせる演出：世界が凍りつき、時が止まる！', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (58, 8, 4, 'ターン4：チームBの砂漠の狂戦士ハディードが必殺技『砂塵の乱舞』でチームAの雷光の忍者リョウに砂の連射を浴びせる演出：砂嵐と共に刃が乱舞する！', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (59, 8, 5, 'ターン5：チームAの大地の巨人ドルグが必殺技『大地割断』でチームBの砂漠の狂戦士ハディードへ地震波を叩き込み撃破演出：大地が唸り、敵の足元が崩れ落ちる！', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (60, 8, 6, 'ターン6：チームBの残り前衛が全滅しチームAが勝利！チームAの紅蓮の剣士アレンが最も活躍しMVPに選出される！', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (61, 9, 1, '紅蓮の剣士アレンは『不死鳥の舞』を使用し、炎で自分を包んで体力を回復し、反撃態勢に入る。', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (62, 9, 2, '鋼鉄の重戦車ゴライアスは『主砲斉射』を発射し、全敵に砲撃を命中させる。', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (63, 9, 3, '氷結の魔女セレナは『絶対零度』を放ち、敵全体を凍りつかせて行動不能に近い状態にする。', 2);
