INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (65, 9, 5, '深海の魔物クラーケンは『触手絡め』で触手で敵を締め上げ、行動を封じる。', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (66, 9, 6, '大地の巨人ドルグは『大地割断』で拳を地面に叩きつけ、衝撃波で敵陣を揺るがす。', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (67, 9, 7, '砂漠の狂戦士ハディードは『砂塵の乱舞』で砂塵を巻き上げ、連続攻撃を繰り広げる。', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (68, 9, 8, '紅蓮の剣士アレンは『紅蓮斬』で炎の刀撃を放ち、敵を薙ぎ払う。', 7);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (69, 10, 1, '鋼鉄の重戦車ゴライアス が 紅蓮の剣士アレン に 主砲斉射 を放ち、炎の砲撃で倒れた！', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (70, 10, 2, '闇夜の暗殺者クロウ が 鋼鉄の重戦車ゴライアス に 闇討ちの一閃 を敢然と使用し、瞬時に倒れた！', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (71, 10, 3, '氷結の魔女セレナ が 絶対零度 を唱え、全敵を凍りつかせる！', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (72, 10, 4, '疾走する機械獣メカウルフ が 雷光の忍者リョウ に 超音速タックル を命中させ、倒れた！', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (73, 10, 5, '砂漠の狂戦士ハディード が 砂塵の乱舞 を繰り出し、大地の巨人ドルグ を砂嵐に飲み込んで倒れた！', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (74, 10, 6, '疾風の弓使いエリカ が 疾風連射 で 疾走する機械獣メカウルフ を貫き、倒れた！', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (75, 10, 7, '聖光の騎士アルフレッド が 聖光の裁き を放ち、深海の魔物クラーケン を光の刃で切り裂いた！', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (76, 10, 8, '毒霧の暗黒術士ヴェノム が 猛毒の霧 を発動し、砂漠の狂戦士ハディード を毒で蝕んで倒れた！', 7);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (77, 11, 1, 'Turn 1: 鋼鉄の重戦車ゴライアスが主砲斉射を放ち、チームA全員に金属の雨のような大ダメージを与える！', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (78, 11, 2, 'Turn 2: 紅蓮の剣士アレンが炎の斬撃で砂漠の狂戦士ハディードに火の粉を吹き付け、体力を削る！', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (79, 11, 3, 'Turn 3: 氷結の魔女セレナが絶対零度で疾走する機械獣メカウルフを凍りつかせ、動きを封じる！', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (80, 11, 4, 'Turn 4: 砂漠の狂戦士ハディードが砂塵の乱舞で大地の巨人ドルグに砂嵐を巻き付け、防御を低下させる！', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (81, 11, 5, 'Turn 5: 雷光の忍者リョウが雷閃刃を放ち、砂漠の狂戦士ハディードに猛き一撃！ハディードは戦闘不能に！', 4);
