INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (85, 13, 1, '【Team A】紅蓮の剣士アレンが『紅蓮斬』で鋼鉄の重戦車ゴライアスに燃える剣撃を叩き込み、炎の閃光が走り抜ける！', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (86, 13, 2, '【Team B】鋼鉄の重戦車ゴライアスは『装甲展開』を発動し、鋼の防御膜を張り上げて一時的に防御力を上げる！', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (87, 13, 3, '【Team B】疾走する機械獣メカウルフが『超音速タックル』で雷光の忍者リョウに突撃、轟音とともに体が吹き飛ぶ！', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (88, 13, 4, '【Team A】氷結の魔女セレナが『絶対零度』を放ち、全敵を凍りつかせて行動不能に近い状態に陥れた！世界が凍りつく！', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (89, 13, 5, '【Team A】大地の巨人ドルグが『大地割断』で地面を叩き割り、衝撃波がクラーケンに直撃！大地が唸りを上げる！', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (90, 13, 6, '【Team B】砂漠の狂戦士ハディードが『砂塵の乱舞』で砂嵐と刃を同時に解き放ち、エリカに連続ダメージを与える！', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (91, 13, 7, '【Team A】紅蓮の剣士アレンが再び『紅蓮斬』でゴライアスの防御を突き破り、最後に『不死鳥の舞』で体力を回復、敵の意気を完全に沈めた！', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (92, 13, 8, '【Result】Team Bの前衛全員が戦闘不能に！Team Aの勝利とともに熱戦が幕を閉じる！', 7);
