INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (95, 14, 3, '氷結の魔女セレナ が 絶対零度 を使用し、全敵に 1 のダメージ！ (ゴライアス HP 13, 疾走する機械獣メカウルフ HP 9, 深海の魔物クラーケン HP 29, 砂漠の狂戦士ハディード HP 14)', 2);
