INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (97, 14, 5, '前衛の雷光の忍者リョウ が 行動不能に！ 闇夜の暗殺者クロウ が 前衛へ補充されました。', 4);
