INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (111, 15, 5, '砂漠の狂戦士ハディードが砂塵の乱舞で大地の巨人ドルグに砂嵐を呼び、倒した！', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (112, 15, 6, '雷光の忍者リョウが雷閃刃で深海の魔物クラーケンに雷光一閃、倒した！', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (113, 15, 7, '砂漠の狂戦士ハディードが砂塵の乱舞で雷光の忍者リョウに砂嵐を叩きつけ、倒した！', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (114, 15, 8, '氷結の魔女セレナが絶対零度で砂漠の狂戦士ハディードを凍りつかせ、行動を封じた！', 7);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (115, 15, 9, '砂漠の狂戦士ハディードが砂塵の乱舞で氷結の魔女セレナに砂嵐を叩き込み、倒した！', 8);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (116, 16, 1, '【激闘開始】Team Aの紅蓮の剣士アレンが炎の刀を振り上げ、「紅蓮斬」を敢行！炎の斬撃が闇を切り裂く――敵陣に燃えさかる光が走る！', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (117, 16, 2, 'Team Bの重装甲重戦車ゴライアスは金属音を鳴らし、「主砲斉射」を放つ！鋼鉄の雷が轟き、前衛全体に直撃する！', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (118, 16, 3, 'Team Aの氷結の魔女セレナは凍りつく瞳で「絶対零度」を呼び出す！世界が氷漬けになり、敵の動きが一瞬凍り付く！', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (119, 16, 4, 'Team Bの疾走する機械獣メカウルフは音速の突進で「超音速タックル」！轟音とともに前列の雷光の忍者リョウを襲い、体が崩れる！', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (120, 16, 5, 'Team Aの雷光の忍者リョウは残りの体力で「雷閃刃」を発動！光速の斬撃が疾走する機械獣を切り裂き、閃光が走る！', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (121, 16, 6, 'Team Bの深海の魔物クラーケンは触手を浮かび上がらせ「触手絡め」！闇の底から伸びた触手がドルグの足元を締め付け、動きを封じる！', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (122, 16, 7, 'Team Aの岩の巨人ドルグは地面を叩き上げ「大地割断」！大地が唸り、触手が揺らぎ、敵の防御が崩れ落ちる！', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (123, 16, 8, '最終的にチームBの全前衛が次々に戦闘不能に！最後の砂漠の狂戦士ハディードさえも氷と雷の連続攻撃で倒れ、激闘はTeam Aの勝利に幕を閉じる！', 7);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (124, 17, 1, '戦闘開始！紅蓮の剣士アレンが「紅蓮斬」で鋼鉄の重戦車ゴрайasに炎の斬撃を放つ。', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (125, 17, 2, '疾走する機械獣メカウルフが「超音速タックル」で雷光の忍者リョウに突撃し、リョウは戦闘不能に。', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (126, 17, 3, '氷結の魔女セレナが「絶対零度」で深海の魔物クラーケンを凍らせ、行動を封じる。', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (127, 17, 4, '深海の魔物クラーケンが「触手絡め」で大地の巨人ドルグを締め付け、動きを止める。', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (128, 17, 5, '砂漠の狂戦士ハディードが「砂塵の乱舞」で紅蓮の剣士アレンに膭波を叩き込み、アレンは倒れる。', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (129, 17, 6, '残った前衛メンバーの復活として、闇夜の暗殺者クロウがランダムで補充され、チームAに 새 frontunit が加入。', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (130, 17, 7, '闇夜の暗殺者クロウが「闇討ちの一閃」で鋼鉄の重戦車ゴraïasに致命的な一撃を与え、ゴraïasは戦闘不能に。', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (131, 17, 8, '聖光の騎士アルフレッドが「守護の誓い」で味方の防御を上げ、逆転の兆しを見せるが、クラーケンの「深海の咆哮」で命中率が低下。', 7);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (132, 17, 9, '疾風の弓使いエリカが「疾風連射」で砂漠の狂戦士ハディードに連続矢を放ち、ハディードを倒す。', 8);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (133, 17, 10, '大地の巨人ドルグが「大地割断」で機械獣メカウルフに衝撃波を叩き込み、メカウルフは戦闘不能に。', 9);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (134, 17, 11, 'チームAの全前衛ユニットが次々に壊滅し、チームBが勝利を確定。', 10);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (135, 17, 12, 'MVPは闇夜の暗殺者クロウ！奇襲の一撃で勝負を変えた。', 11);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (136, 18, 1, '紅蓮の剣士アレンが「紅蓮斬」を使用し、鋼鉄の重戦車ゴライアスに炎の斬撃が炸裂！', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (137, 18, 2, '疾走する機械獣メカウルフが「超音速タックル」で紅蓮の剣士アレンを倒した！', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (138, 18, 3, '深海の魔物クラーケンが「触手絡め」で大地の巨人ドルグを締め上げた！', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (139, 18, 4, '氷結の魔女セレナが「絶対零度」で深海の魔物クラーケンを凍りつかせた！', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (140, 18, 5, '鋼鉄の重戦車ゴライアスが「主砲斉射」で雷光の忍者リョウを炸裂させた！', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (141, 18, 6, '砂漠の狂戦士ハディードが「砂塵の乱舞」で疾風の弓使いエリカを襲った！', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (142, 18, 7, '大地の巨人が「大地割断」で砂漠の狂戦士ハディードを叩き砕いた！', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (143, 18, 8, '疾走する機械獣メカウルフが「超音速タックル」で大地の巨人ドルグを倒した！', 7);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (144, 18, 9, '鋼鉄の重戦車ゴライアスが「装甲展開」で防御力を高めた！', 8);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (145, 18, 10, '深海の魔物クラーケンが「深海の咆哮」で闇夜の暗殺者クロウを威圧した！', 9);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (146, 18, 11, '聖光の騎士アルフレッドが「聖光の裁き」で鋼鉄の重戦車ゴライアスを撃破した！', 10);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (147, 18, 12, '闇夜の暗殺者クロウが「闇討ちの一閃」で深海の魔物クラーケンを貫いた！', 11);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (148, 18, 13, '業火の竜人イグニスが「滅焦竜炎」で氷結の魔女セレナを焼き尽くした！', 12);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (149, 18, 14, '疾走する機械獣メカウルフが「超音速タックル」で闇夜の暗殺者クロウを倒した！', 13);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (150, 18, 15, '聖光の騎士アルフレッドが「聖光の裁き」で疾走する機械獣メカウルフを撃破した！', 14);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (151, 18, 16, '月光の巫女ルナが「月光浄化」で毒霧の暗黒術士ヴェノムを浄化した！', 15);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (152, 18, 17, '業火の竜人イグニスが「滅焦竜炎」で聖光の騎士アルフレッドを炎上させた！', 16);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (153, 20, 1, '第1ターン：紅蓮の剣士アレンがゴライアスに 紅蓮斬 を使用しゴライアスが戦闘不能になった。鋼鉄の重戦車ゴライアスが主砲斉射を使用したがしばらく後に疾走する機械獣メカウルフが超音速タックルでセレナが戦闘不能になった。氷結の魔女セレナが絶対零度を使用したがすぐに大地の巨人ドルグが大地割断を使用しクラーケンとハディードに衝撃を与えクラーケンが戦闘不能になった。闇夜の暗殺者クロウが闇討ちの一閃でリョウに決定的ダメージを与えリョウが戦闘不能になった。残りのドルグが砂塵の乱舞によりハディードに決定的ダメージを与えハディードが戦闘不能になった。Team B全員が前衛で戦闘不能となりTeam Aの勝利が決定。', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (154, 21, 1, '紅蓮の剣士アレンが炎の刀で『紅蓮斬』を放ち、鋼鉄の重戦車ゴライアスの装甲を切り裂く！燃えるような斬撃が鋼の壁に突き刺さった！', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (155, 21, 2, '砂漠の狂戦士ハディードが砂嵐と刀を同時に舞い踊る『砂塵の乱舞』で、氷結の魔女セレナと雷光の忍者リョウに砂の刃が命中し、体力を削った！', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (156, 21, 3, '氷結の魔女セレナが凍りつく大地から『絶対零度』を呼び寄せ、疾走する機械獣メカウルフの足を氷で締め付け、動きを封じた！', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (157, 21, 4, '雷光の忍者リョウが光速の一閃で『雷閃刃』を放ち、砂漠の狂戦士ハディードの胸部を貫く！砂漠の狂戦士ハディードが戦闘不能になった', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (158, 21, 5, '紅蓮の剣士アレンが再び炎の刀で『紅蓮斬』を放ち、鋼鉄の重戦車ゴライアスの胸部を貫く！鋼鉄の重戦車ゴライアスが戦闘不能になった', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (159, 21, 6, '大地の巨人ドルグが拳で『大地割断』を叩き込み、深海の魔物クラーケンの触手を砕き、深海の魔物クラーケンが戦闘不能になった', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (160, 21, 7, '疾走する機械獣メカウルフが凍結と衝撃で消滅し、疾走する機械獣メカウルフが戦闘不能になった', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (161, 23, 1, '戦闘開始！ 紅蓮の剣士アレンが必殺技『紅蓮斬』を発動し、鋼鉄の重戦車ゴрайásに炎の斬撃を叩き込んだ。続く鋼鉄の重戦車ゴрайásは必殺技『主砲斉射』を発動し、チームA全体に砲撃を放った。氷結の魔女セレナは必殺技『絶対零度』を発動し、深海の魔物クラーケンを凍りつかせた。雷光の忍者リョウは必殺技『雷閃刃』を発動し、疾走する機械獣メカウルフに雷光一閃を食らわせた。', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (162, 23, 2, '大地の巨人ドルグが必殺技『不死鳥の舞』を発動し、体力を回復しながら反撃態勢に入った。闇夜の暗殺者クロウは必殺技『闇討ちの一閃』を発動し、遠距離から突如として襲撃を仕掛けた。', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (163, 23, 3, '聖光の騎士アルフレッドが必殺技『聖光の裁き』を発動し、ドルグに大ダメージを与えた。', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (164, 23, 4, '深海の魔物クラーケンが戦闘不能になった。闇夜の暗殺者クロウが代わりに前衛へ補充された。', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (165, 23, 5, '雷光の忍者リョウが必殺技『雷閃刃』を再び発動し、残りの前衛を次々と倒した。', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (166, 23, 6, 'チームA全員が戦闘不能になった。チームBの勝利だ！', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (167, 29, 1, '戦闘開始！ 行動順はランダムに決定された。センゴクンが通常攻撃で紅蓮の剣士アレンに強烈なキックを叩き込んだ。防御の低いアレンは大きくよろめいた。氷結の魔女セレナは通常攻撃でシライに冷気弾を放った。イワルンはすばやい身のこなしで雷光の忍者リョウの攻撃をかわしつつ体当たりを返した。', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (168, 29, 2, 'シライが必殺技『ストロングウォーク』を発動し、仲間の体力を回復しながら味方全体の防御力を2段階上げた。チームあしたばの前衛が硬くなった。', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (169, 29, 3, '紅蓮の剣士アレンが必殺技『紅蓮斬』を発動し、シライに炎の斬撃を放った。防御力が上がっていたシライだったが、それでも大きく怯んだ。', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (170, 29, 4, 'センゴクンが必殺技『レア・エンカウント・キャノン』を発動し、大地の巨人ドルグへ重力をねじ曲げるほどのエネルギー弾を撃ち込んだ。高い防御力を誇るドルグは何とか耐えきったが、素早さが低くまともに直撃を受けてしまった。', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (171, 29, 5, '雷光の忍者リョウが必殺技『雷閃刃』を発動し、タシロップに雷速の斬撃を放った。ドリブルとリーチに特化し打たれ弱いタシロップは受け止めきれず、タシロップが戦闘不能になった。タニョンが代わりに前衛へ補充された。', 4);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (172, 29, 6, 'イワルンが必殺技『クレバー・スピード』を発動し、相手の動きを完璧に予測して氷結の魔女セレナへ回り込みながら体当たりを見舞った。魔力に特化し防御が薄いセレナは大きくよろめいた。', 5);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (173, 29, 7, '氷結の魔女セレナが必殺技『絶対零度』を発動し、チームあしたばの前衛全体を凍りつかせた。動きを封じられたイワルンとタニョンは反撃もままならず苦しんだ。', 6);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (174, 29, 8, 'センゴクンが必殺技『ルーティン・バースト』を再び発動し、雷光の忍者リョウへ超重量級の体当たりを浴びせた。素早さに極振りし防御が低いリョウは耐えきれず、雷光の忍者リョウが戦闘不能になった。闇夜の暗殺者クロウが代わりに前衛へ補充された。', 7);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (175, 29, 9, '闇夜の暗殺者クロウが必殺技『闇討ちの一閃』を発動し、隙を見せたセンゴクンの急所を貫いた。持続力はあっても奇襲に弱いセンゴクンは大ダメージを受け、センゴクンが戦闘不能になった。ネギルじいが代わりに前衛へ補充された。同じ頃、大地の巨人ドルグの拳を受け続けたシライも力尽き、シライが戦闘不能になった。カネマールが代わりに前衛へ補充された。', 8);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (176, 29, 10, '紅蓮の剣士アレンが必殺技『紅蓮斬』を再び発動し、残る前衛のイワルン・タニョン・ネギルじい・カネマールへ次々と炎の斬撃を浴びせた。戦闘向きの耐久力を持たない面々は耐えきれず、イワルン、タニョン、ネギルじい、カネマールが戦闘不能になった。チームあしたば全員が戦闘不能になった。チームAの勝利だ！', 9);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (177, 30, 1, '鋼鉄の重戦車ゴライアスが必殺技『主砲斉射』を発動し、シライに大ダメージを与えた。', 0);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (178, 30, 2, 'イワルンが必殺技『万能スターダスト』を発動し、team B全体の防御力を下げる効果を発射した。', 1);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (179, 30, 3, '疾走する機械獣メカウルフが必殺技『超音速タックル』を発動し、イワルンが戦闘不能になった。', 2);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (180, 30, 4, 'タシロップが必殺技『終わりなき美メロ』を発動し、シライが戦闘不能になった。', 3);
INSERT INTO battle_logs (id, battle_id, turn, message, sort_order) VALUES (181, 30, 5, '砂漠の狂戦士ハディードが必殺技『砂塵の乱舞』を発動し、残る敵に大打撃を与えた。team Aの勝利だ！！', 4);
