-- SQLite側の内容(id込み)で置き換える。phpMyAdminのSQLタブ等で一度だけ実行すること。
-- 実行前提: php/migrate.php(schema.sql)でテーブルが作成済みであること。

SET FOREIGN_KEY_CHECKS=0;
START TRANSACTION;

DELETE FROM battle_events;
DELETE FROM battle_logs;
DELETE FROM battles;
DELETE FROM deck_cards;
DELETE FROM decks;
DELETE FROM special_moves;
DELETE FROM character_parameters;
DELETE FROM characters;

