-- AUTO_INCREMENTを移行データの最大id+1へ合わせる(以後のINSERTがidと衝突しないように)
ALTER TABLE characters AUTO_INCREMENT = 27;
ALTER TABLE character_parameters AUTO_INCREMENT = 141;
ALTER TABLE special_moves AUTO_INCREMENT = 65;
ALTER TABLE decks AUTO_INCREMENT = 5;
ALTER TABLE deck_cards AUTO_INCREMENT = 57;
ALTER TABLE battles AUTO_INCREMENT = 31;
ALTER TABLE battle_logs AUTO_INCREMENT = 182;
ALTER TABLE battle_events AUTO_INCREMENT = 160;

COMMIT;
SET FOREIGN_KEY_CHECKS=1;

